  1→using System.ComponentModel;
  2→using System.Drawing;
  3→using Terminal.Gui.Drawing;
  4→using Terminal.Gui.Text.Document;
  5→using Terminal.Gui.ViewBase;
  6→
  7→namespace Terminal.Gui.Views;
  8→
  9→/// <summary>
 10→///     Single-document text editor View backed by <see cref="TextDocument" />. Renders multi-line
 11→///     text from a rope-backed document, tracks a caret offset, dispatches keyboard input to
 12→///     navigate / edit, and scrolls content when it exceeds the viewport. Pre-MVP — selection,
 13→///     folding, syntax highlighting still pending per <c>specs/00-plan.md</c>.
 14→/// </summary>
 15→public partial class Editor : View
 16→{
 17→    private int _caretOffset;
 18→    private TextDocument? _document;
 19→    private bool _showLineNumbers;
 20→    private ISyntaxHighlighter? _syntaxHighlighter;
 21→
 22→    /// <summary>
 23→    ///     Sticky column for vertical caret moves. Tracks the column the user *intends* to be in,
 24→    ///     even when the current line is shorter, so Up/Down across short lines snap back to the
 25→    ///     original column on the first long line.
 26→    /// </summary>
 27→    private int _virtualCaretColumn;
 28→
 29→    /// <summary>Initializes a new <see cref="Editor" /> with an empty <see cref="TextDocument" />.</summary>
 30→    public Editor ()
 31→    {
 32→        CanFocus = true;
 33→        CreateCommandsAndBindings ();
 34→        Document = new ();
 35→    }
 36→
 37→    /// <summary>The backing <see cref="TextDocument" />. Setting this rewires change handlers and clamps the caret.</summary>
 38→    public TextDocument? Document
 39→    {
 40→        get => _document;
 41→        set
 42→        {
 43→            ArgumentNullException.ThrowIfNull (value);
 44→
 45→            if (ReferenceEquals (_document, value))
 46→            {
 47→                return;
 48→            }
 49→
 50→            if (_document is not null)
 51→            {
 52→                _document.Changed -= OnDocumentChanged;
 53→            }
 54→
 55→            _document = value;
 56→            _document.Changed += OnDocumentChanged;
 57→
 58→            _caretOffset = Math.Clamp (_caretOffset, 0, _document.TextLength);
 59→            _virtualCaretColumn = GetCaretColumn ();
 60→            UpdateContentSize ();
 61→            UpdateLineNumberPadding ();
 62→            SetNeedsDraw ();
 63→        }
 64→    }
 65→
 66→    /// <summary>
 67→    ///     Current caret offset. Clamped to <c>[0, Document.TextLength]</c>. Setting this scrolls the
 68→    ///     viewport to keep the caret visible and raises <see cref="CaretChanged" />.
 69→    /// </summary>
 70→    public int CaretOffset
 71→    {
 72→        get => _caretOffset;
 73→        set => SetCaretOffset (value, true);
 74→    }
 75→
 76→    /// <summary>
 77→    ///     Gets or sets whether one-based line numbers are rendered in the editor's left padding.
 78→    /// </summary>
 79→    public bool ShowLineNumbers
 80→    {
 81→        get => _showLineNumbers;
 82→        set
 83→        {
 84→            if (_showLineNumbers == value)
 85→            {
 86→                return;
 87→            }
 88→
 89→            _showLineNumbers = value;
 90→            UpdateLineNumberPadding ();
 91→            SetNeedsDraw ();
 92→        }
 93→    }
 94→
 95→    /// <summary>
 96→    ///     Optional syntax highlighter used when drawing document text.
 97→    ///     Optional syntax highlighter used when drawing document text.
 98→    /// </summary>
 99→    /// <remarks>
100→    ///     <para>
101→    ///         <b>Stopgap.</b> This property reuses Terminal.Gui's
102→    ///         <see cref="ISyntaxHighlighter" /> from <c>Terminal.Gui.Drawing.Markdown</c>, which is
103→    ///         shaped for Markdown rendering — not for an editor's per-line / per-visual-line
104→    ///         highlighting pipeline. It will be removed when <c>specs/00-plan.md</c> Phase 6 lifts
105→    ///         AvaloniaEdit's <c>Highlighting/</c> folder and the editor switches to a
106→    ///         <c>HighlightingColorizer : IVisualLineTransformer</c> running over the
107→    ///         <see cref="DocumentLine" /> → visual-line pipeline tracked by issue #28.
108→    ///     </para>
109→    ///     <para>
110→    ///         External code should not take a hard dependency on this contract.
111→    ///     </para>
112→    /// </remarks>
113→    [Obsolete (
114→        "Stopgap reusing Terminal.Gui's Markdown ISyntaxHighlighter; will be replaced by HighlightingColorizer when specs/00-plan.md Phase 6 lifts AvaloniaEdit's Highlighting/ folder. See issue #28 for the visual-line pipeline that replaces this. Tracked by issue #32.")]
115→    [EditorBrowsable (EditorBrowsableState.Never)]
116→    public ISyntaxHighlighter? SyntaxHighlighter
117→    {
118→        get => _syntaxHighlighter;
119→        set
120→        {
121→            if (ReferenceEquals (_syntaxHighlighter, value))
122→            {
123→                return;
124→            }
125→
126→            _syntaxHighlighter = value;
127→            _syntaxHighlighter?.ResetState ();
128→            SetNeedsDraw ();
129→        }
130→    }
131→
132→    /// <summary>The language identifier passed to <see cref="SyntaxHighlighter" />. Defaults to C#.</summary>
133→    /// <remarks>
134→    ///     Obsolete for the same reason as <see cref="SyntaxHighlighter" /> — this is part of the
135→    ///     temporary Markdown-shaped surface that Phase 6 will replace. See issue #28 / #32.
136→    /// </remarks>
137→    [Obsolete (
138→        "Stopgap reusing Terminal.Gui's Markdown ISyntaxHighlighter; will be replaced by HighlightingColorizer when specs/00-plan.md Phase 6 lifts AvaloniaEdit's Highlighting/ folder. See issue #28 for the visual-line pipeline that replaces this. Tracked by issue #32.")]
139→    [EditorBrowsable (EditorBrowsableState.Never)]
140→    public string SyntaxLanguage
141→    {
142→        get;
143→        set
144→        {
145→            ArgumentNullException.ThrowIfNull (value);
146→
147→            if (field == value)
148→            {
149→                return;
150→            }
151→
152→            field = value;
153→            _syntaxHighlighter?.ResetState ();
154→            SetNeedsDraw ();
155→        }
156→    } = "csharp";
157→
158→    /// <summary>Visual tab-stop width in cells. Defaults to 4.</summary>
159→    public int TabWidth
160→    {
161→        get;
162→        set
163→        {
164→            ArgumentOutOfRangeException.ThrowIfLessThan (value, 1);
165→
166→            if (field == value)
167→            {
168→                return;
169→            }
170→
171→            field = value;
172→            _virtualCaretColumn = GetCaretColumn ();
173→            UpdateContentSize ();
174→            EnsureCaretVisible ();
175→            SetNeedsDraw ();
176→        }
177→    } = 4;
178→
179→    /// <summary>Raised whenever <see cref="CaretOffset" /> changes.</summary>
180→    public event EventHandler? CaretChanged;
181→
182→    private void SetCaretOffset (int value, bool resetVirtualColumn)
183→    {
184→        var clamped = Math.Clamp (value, 0, _document?.TextLength ?? 0);
185→
186→        if (clamped == _caretOffset && !resetVirtualColumn)
187→        {
188→            return;
189→        }
190→
191→        var changed = clamped != _caretOffset;
192→        _caretOffset = clamped;
193→
194→        if (resetVirtualColumn)
195→        {
196→            _virtualCaretColumn = GetCaretColumn ();
197→        }
198→
199→        EnsureCaretVisible ();
200→        SetNeedsDraw ();
201→
202→        if (changed)
203→        {
204→            CaretChanged?.Invoke (this, EventArgs.Empty);
205→        }
206→    }
207→
208→    /// <inheritdoc />
209→    protected override void Dispose (bool disposing)
210→    {
211→        if (disposing && _document is not null)
212→        {
213→            // Without this the document keeps the editor alive via the Changed subscription whenever
214→            // external code retains the TextDocument (test fixtures, future shared docs across panes,
215→            // etc.). The Document setter unsubscribes on swap; this covers View-teardown.
216→            _document.Changed -= OnDocumentChanged;
217→        }
218→
219→        base.Dispose (disposing);
220→    }
221→
222→    private void OnDocumentChanged (object? sender, DocumentChangeEventArgs e)
223→    {
224→        // Content-size has to refresh first so EnsureCaretVisible inside SetCaretOffset clamps the
225→        // viewport against the new line count.
226→        UpdateContentSize ();
227→
228→        // Manual stand-in for TextAnchor.AfterInsertion until specs/00-plan.md §6 lands. The math:
229→        // an insert at-or-before the caret pushes it forward by InsertionLength; an insert strictly
230→        // after the caret leaves it alone; a removal that straddles the caret snaps it to the
231→        // removal start; a removal entirely before the caret slides it back by RemovalLength.
232→        if (_caretOffset >= e.Offset)
233→        {
234→            var target = _caretOffset < e.Offset + e.RemovalLength
235→                ? e.Offset
236→                : _caretOffset - e.RemovalLength + e.InsertionLength;
237→
238→            // Route through SetCaretOffset so CaretChanged fires when the caret actually moves.
239→            // SetCaretOffset also handles EnsureCaretVisible + SetNeedsDraw.
240→            SetCaretOffset (target, true);
241→
242→            return;
243→        }
244→
245→        UpdateContentSize ();
246→        UpdateLineNumberPadding ();
247→        EnsureCaretVisible ();
248→        SetNeedsDraw ();
249→    }
250→
251→    private void UpdateContentSize ()
252→    {
253→        if (_document == null)
254→        {
255→            return;
256→        }
257→
258→        var maxWidth = _document.Lines.Select (line => GetVisualColumnFromLogicalColumn (line, line.Length)).Prepend (0)
259→            .Max ();
260→
261→        // +1 column lets the caret sit just past the end-of-line.
262→        SetContentSize (new (maxWidth + 1, _document.LineCount));
263→    }
264→
265→    private void UpdateLineNumberPadding ()
266→    {
267→        Thickness thickness = Padding.Thickness;
268→        var left = _showLineNumbers && _document is not null ? GetLineNumberPaddingWidth () : 0;
269→
270→        if (thickness.Left == left)
271→        {
272→            return;
273→        }
274→
275→        Padding.Thickness = new (left, thickness.Top, thickness.Right, thickness.Bottom);
276→    }
277→
278→    private int GetLineNumberPaddingWidth ()
279→    {
280→        var lineCount = Math.Max (1, _document?.LineCount ?? 1);
281→
282→        return lineCount.ToString ().Length + 1;
283→    }
284→
285→    private int GetCaretColumn ()
286→    {
287→        DocumentLine? line = _document?.GetLineByOffset (_caretOffset);
288→
289→        if (line is null)
290→        {
291→            return 0;
292→        }
293→
294→        var logicalColumn = _caretOffset - line.Offset;
295→
296→        return GetVisualColumnFromLogicalColumn (line, logicalColumn);
297→    }
298→
299→    private int GetCaretLineIndex ()
300→    {
301→        return _document?.GetLineByOffset (_caretOffset).LineNumber - 1 ?? 0;
302→    }
303→
304→    /// <summary>
305→    ///     Moves the caret <paramref name="delta" /> lines, preserving the sticky virtual column when
306→    ///     traversing shorter lines (i.e. snap back to the original column on the next long-enough line).
307→    /// </summary>
308→    private void MoveCaretVertically (int delta)
309→    {
310→        var targetLine = Math.Clamp (GetCaretLineIndex () + delta, 0, _document!.LineCount - 1);
311→        DocumentLine line = _document!.GetLineByNumber (targetLine + 1);
312→        var targetCol = GetLogicalColumnFromVisualColumn (line, _virtualCaretColumn);
313→
314→        // resetVirtualColumn: false keeps the sticky column intact across vertical moves.
315→        SetCaretOffset (line.Offset + targetCol, false);
316→    }
317→
318→    private int GetVisualColumnFromLogicalColumn (DocumentLine line, int logicalColumn)
319→    {
320→        var text = _document!.GetText (line);
321→        var clampedLogical = Math.Clamp (logicalColumn, 0, text.Length);
322→        var visualColumn = 0;
323→
324→        for (var i = 0; i < clampedLogical; i++)
325→        {
326→            visualColumn += GetVisualWidthForCharacter (text[i], visualColumn, TabWidth);
327→        }
328→
329→        return visualColumn;
330→    }
331→
332→    private int GetLogicalColumnFromVisualColumn (DocumentLine line, int visualColumn)
333→    {
334→        var text = _document!.GetText (line);
335→        var clampedVisual = Math.Max (0, visualColumn);
336→        var currentVisual = 0;
337→
338→        for (var logical = 0; logical < text.Length; logical++)
339→        {
340→            var width = GetVisualWidthForCharacter (text[logical], currentVisual, TabWidth);
341→            var nextVisual = currentVisual + width;
342→
343→            if (nextVisual >= clampedVisual)
344→            {
345→                if (text[logical] == '\t' && clampedVisual > currentVisual)
346→                {
347→                    // Clicking or moving inside the visual span produced by '\t' snaps the caret
348→                    // after the tab character because there is no representable position "inside"
349→                    // a single tab code point.
350→                    return logical + 1;
351→                }
352→
353→                return clampedVisual >= nextVisual ? logical + 1 : logical;
354→            }
355→
356→            currentVisual = nextVisual;
357→        }
358→
359→        return text.Length;
360→    }
361→
362→    private static int GetVisualWidthForCharacter (char c, int visualColumn, int tabWidth)
363→    {
364→        if (c != '\t')
365→        {
366→            return 1;
367→        }
368→
369→        var remainder = visualColumn % tabWidth;
370→
371→        return remainder == 0 ? tabWidth : tabWidth - remainder;
372→    }
373→
374→    private void EnsureCaretVisible ()
375→    {
376→        Rectangle viewport = Viewport;
377→
378→        if (viewport.Width == 0 || viewport.Height == 0)
379→        {
380→            return;
381→        }
382→
383→        var caretLine = GetCaretLineIndex ();
384→        var caretCol = GetCaretColumn ();
385→        var newY = viewport.Y;
386→        var newX = viewport.X;
387→
388→        if (caretLine < newY)
389→        {
390→            newY = caretLine;
391→        }
392→        else if (caretLine >= newY + viewport.Height)
393→        {
394→            newY = caretLine - viewport.Height + 1;
395→        }
396→
397→        if (caretCol < newX)
398→        {
399→            newX = caretCol;
400→        }
401→        else if (caretCol >= newX + viewport.Width)
402→        {
403→            newX = caretCol - viewport.Width + 1;
404→        }
405→
406→        if (newX != viewport.X || newY != viewport.Y)
407→        {
408→            Viewport = viewport with { X = newX, Y = newY };
409→        }
410→    }
411→}
