  1→using System.Drawing;
  2→using Terminal.Gui.Drawing;
  3→using Terminal.Gui.Drivers;
  4→using Terminal.Gui.Text.Document;
  5→using Terminal.Gui.ViewBase;
  6→using Attribute = Terminal.Gui.Drawing.Attribute;
  7→
  8→namespace Terminal.Gui.Views;
  9→
 10→public partial class Editor
 11→{
 12→    /// <inheritdoc />
 13→    protected override bool OnDrawingContent (DrawContext? context)
 14→    {
 15→        if (_document is null)
 16→        {
 17→            return true;
 18→        }
 19→
 20→        Rectangle viewport = Viewport;
 21→        Attribute normal = GetAttributeForRole (VisualRole.Normal);
 22→        Attribute selected = GetAttributeForRole (VisualRole.Active);
 23→
 24→        // The CS0618 here is the API's purpose: SyntaxHighlighter is [Obsolete] to warn
 25→        // external callers that this is a stopgap (issue #32). The editor itself still has to
 26→        // honor the property until Phase 6 lifts AvaloniaEdit's Highlighting/ pipeline (#28).
 27→#pragma warning disable CS0618 // Type or member is obsolete
 28→        ISyntaxHighlighter? syntaxHighlighter = SyntaxHighlighter;
 29→#pragma warning restore CS0618 // Type or member is obsolete
 30→
 31→        var hasSelection = HasSelection;
 32→        var selStart = hasSelection ? SelectionStart : 0;
 33→        var selEnd = hasSelection ? SelectionEnd : 0;
 34→
 35→        PrepareSyntaxHighlighter (syntaxHighlighter, viewport.Y);
 36→
 37→        for (var row = 0; row < viewport.Height; row++)
 38→        {
 39→            var lineIndex = viewport.Y + row;
 40→
 41→            if (lineIndex < 0 || lineIndex >= _document.LineCount)
 42→            {
 43→                break;
 44→            }
 45→
 46→            DocumentLine line = _document.GetLineByNumber (lineIndex + 1);
 47→            var text = _document.GetText (line);
 48→#pragma warning disable CS0618 // Type or member is obsolete — see note at top of OnDrawingContent.
 49→            IReadOnlyList<StyledSegment>? segments = syntaxHighlighter?.Highlight (text, SyntaxLanguage);
 50→#pragma warning restore CS0618 // Type or member is obsolete
 51→            var visibleStart = viewport.X;
 52→            var visibleEnd = viewport.X + viewport.Width;
 53→
 54→            DrawLineContent (
 55→                row,
 56→                text,
 57→                visibleStart,
 58→                visibleEnd,
 59→                segments,
 60→                normal,
 61→                selected,
 62→                line.Offset,
 63→                hasSelection,
 64→                selStart,
 65→                selEnd);
 66→        }
 67→
 68→        SetAttribute (normal);
 69→        UpdateCursor ();
 70→
 71→        return true;
 72→    }
 73→
 74→    private void PrepareSyntaxHighlighter (ISyntaxHighlighter? syntaxHighlighter, int firstVisibleLineIndex)
 75→    {
 76→        if (syntaxHighlighter is null || _document is null)
 77→        {
 78→            return;
 79→        }
 80→
 81→        syntaxHighlighter.ResetState ();
 82→
 83→        for (var lineIndex = 0; lineIndex < firstVisibleLineIndex && lineIndex < _document.LineCount; lineIndex++)
 84→        {
 85→            DocumentLine line = _document.GetLineByNumber (lineIndex + 1);
 86→#pragma warning disable CS0618 // Type or member is obsolete — see note in OnDrawingContent.
 87→            syntaxHighlighter.Highlight (_document.GetText (line), SyntaxLanguage);
 88→#pragma warning restore CS0618 // Type or member is obsolete
 89→        }
 90→    }
 91→
 92→    private void DrawLineContent (
 93→        int row,
 94→        string text,
 95→        int visibleStart,
 96→        int visibleEnd,
 97→        IReadOnlyList<StyledSegment>? segments,
 98→        Attribute normal,
 99→        Attribute selected,
100→        int lineOffset,
101→        bool hasSelection,
102→        int selStart,
103→        int selEnd)
104→    {
105→        var visualColumn = 0;
106→        var segmentIndex = 0;
107→        var segmentEnd = segments is { Count: > 0 } ? segments[0].Text.Length : int.MaxValue;
108→
109→        for (var i = 0; i < text.Length; i++)
110→        {
111→            while (segments is not null && i >= segmentEnd && segmentIndex + 1 < segments.Count)
112→            {
113→                segmentIndex++;
114→                segmentEnd += segments[segmentIndex].Text.Length;
115→            }
116→
117→            Attribute attribute = segments is null
118→                ? normal
119→                : segments[segmentIndex].Attribute ?? normal;
120→
121→            if (hasSelection && lineOffset + i >= selStart && lineOffset + i < selEnd)
122→            {
123→                attribute = selected;
124→            }
125→
126→            var c = text[i];
127→            var width = GetVisualWidthForCharacter (c, visualColumn, TabWidth);
128→            var charVisualStart = visualColumn;
129→            var charVisualEnd = visualColumn + width;
130→
131→            if (charVisualEnd <= visibleStart)
132→            {
133→                visualColumn = charVisualEnd;
134→
135→                continue;
136→            }
137→
138→            if (charVisualStart >= visibleEnd)
139→            {
140→                break;
141→            }
142→
143→            var drawStart = Math.Max (charVisualStart, visibleStart);
144→            var drawEnd = Math.Min (charVisualEnd, visibleEnd);
145→
146→            if (drawEnd > drawStart)
147→            {
148→                SetAttribute (attribute);
149→                AddStr (
150→                    drawStart - visibleStart,
151→                    row,
152→                    c == '\t' ? new (' ', drawEnd - drawStart) : c.ToString ());
153→            }
154→
155→            visualColumn = charVisualEnd;
156→        }
157→    }
158→
159→    private void UpdateCursor ()
160→    {
161→        if (!HasFocus || _document is null)
162→        {
163→            Cursor = new ();
164→
165→            return;
166→        }
167→
168→        Rectangle viewport = Viewport;
169→        var caretLine = GetCaretLineIndex ();
170→        var caretCol = GetCaretColumn ();
171→        var row = caretLine - viewport.Y;
172→        var col = caretCol - viewport.X;
173→
174→        if (row < 0 || row >= viewport.Height || col < 0 || col >= viewport.Width)
175→        {
176→            Cursor = new ();
177→
178→            return;
179→        }
180→
181→        Point screen = ViewportToScreen (new Point (col, row));
182→        Cursor = new () { Position = screen, Style = CursorStyle.BlinkingBar };
183→    }
184→
185→    /// <inheritdoc />
186→    protected override void OnDrawComplete (DrawContext? context)
187→    {
188→        base.OnDrawComplete (context);
189→
190→        if (App?.Driver is { } driver)
191→        {
192→            DrawLineNumbers (driver);
193→        }
194→    }
195→
196→    private void DrawLineNumbers (IDriver driver)
197→    {
198→        if (!_showLineNumbers || _document is null)
199→        {
200→            return;
201→        }
202→
203→        var width = Padding.Thickness.Left;
204→
205→        if (width <= 0)
206→        {
207→            return;
208→        }
209→
210→        Rectangle viewport = Viewport;
211→        Rectangle screen = ViewportToScreen ();
212→        Region? clip = GetClip ();
213→        Attribute previous = driver.SetAttribute (GetAttributeForRole (VisualRole.Normal));
214→
215→        SetClipToScreen ();
216→
217→        try
218→        {
219→            for (var row = 0; row < viewport.Height; row++)
220→            {
221→                var lineIndex = viewport.Y + row;
222→                var text = lineIndex < _document.LineCount
223→                    ? (lineIndex + 1).ToString ().PadLeft (width - 1).PadRight (width)
224→                    : new string (' ', width);
225→
226→                driver.Move (screen.X - width, screen.Y + row);
227→                driver.AddStr (text);
228→            }
229→        }
230→        finally
231→        {
232→            if (clip is not null)
233→            {
234→                SetClip (clip);
235→            }
236→
237→            driver.SetAttribute (previous);
238→        }
239→    }
240→}
