 1→using System.Text;
 2→using Terminal.Gui.Input;
 3→
 4→namespace Terminal.Gui.Views;
 5→
 6→public partial class Editor
 7→{
 8→    /// <summary>
 9→    ///     Catches keystrokes that didn't match any registered <see cref="Command" /> binding (set up in
10→    ///     <see cref="CreateCommandsAndBindings" />) and inserts the typed rune into the document. Skips
11→    ///     modified keys and control characters — those are either bound elsewhere or not editor input.
12→    /// </summary>
13→    /// <inheritdoc />
14→    protected override bool OnKeyDownNotHandled (Key key)
15→    {
16→        if (key.IsCtrl || key.IsAlt)
17→        {
18→            return false;
19→        }
20→
21→        // Rune.IsControl already covers U+0000 (default(Rune)), so no explicit NUL guard is needed.
22→        if (key is not { AsRune: { } rune } || Rune.IsControl (rune))
23→        {
24→            return false;
25→        }
26→
27→        if (HasSelection)
28→        {
29→            ReplaceSelection (rune.ToString ());
30→        }
31→        else
32→        {
33→            _document!.Insert (_caretOffset, rune.ToString ());
34→        }
35→
36→        return true;
37→    }
38→}
