 1→using System.Drawing;
 2→using Terminal.Gui.Input;
 3→using Terminal.Gui.Text.Document;
 4→
 5→namespace Terminal.Gui.Views;
 6→
 7→public partial class Editor
 8→{
 9→    /// <inheritdoc />
10→    protected override bool OnMouseEvent (Mouse mouse)
11→    {
12→        if (_document is null)
13→        {
14→            return false;
15→        }
16→
17→        if (mouse.Position is not { } pos)
18→        {
19→            return false;
20→        }
21→
22→        var shift = mouse.Flags.HasFlag (MouseFlags.Shift);
23→
24→        // Drag: left button held while position changes — extend selection from the press point.
25→        // Tested first because PositionReport+LeftButtonPressed also satisfies the plain-press check.
26→        if (mouse.Flags.FastHasFlags (MouseFlags.LeftButtonPressed | MouseFlags.PositionReport))
27→        {
28→            var offset = MousePositionToOffset (pos);
29→
30→            // Route through the selection helper so SelectionChanged fires only on real changes.
31→            ExtendCaretTo (offset);
32→
33→            return true;
34→        }
35→
36→        // Press: focus, place caret, optionally start a selection (shift) or clear it (plain).
37→        if (mouse.Flags.HasFlag (MouseFlags.LeftButtonPressed))
38→        {
39→            if (CanFocus && !HasFocus)
40→            {
41→                SetFocus ();
42→            }
43→
44→            var offset = MousePositionToOffset (pos);
45→
46→            if (shift)
47→            {
48→                ExtendCaretTo (offset);
49→            }
50→            else
51→            {
52→                ClearSelection ();
53→                CaretOffset = offset;
54→            }
55→
56→            // Grab the mouse so subsequent drag/release events route here even if the cursor leaves
57→            // this view's bounds — TG's default routing only delivers events to the view under the
58→            // pointer, which would break the drag-to-select gesture mid-stroke.
59→            App?.Mouse.GrabMouse (this);
60→
61→            return true;
62→        }
63→
64→        // Release: end the drag-grab so other views start receiving events again.
65→        if (mouse.Flags.HasFlag (MouseFlags.LeftButtonReleased))
66→        {
67→            App?.Mouse.UngrabMouse ();
68→
69→            return true;
70→        }
71→
72→        return false;
73→    }
74→
75→    /// <summary>
76→    ///     Converts a viewport-relative <see cref="Point" /> into a clamped document offset. Mouse events
77→    ///     past the end of a line snap to that line's end; clicks below the last line snap to the last line.
78→    /// </summary>
79→    private int MousePositionToOffset (Point viewPos)
80→    {
81→        if (_document is null || _document.LineCount == 0)
82→        {
83→            return 0;
84→        }
85→
86→        var lineIndex = Math.Clamp (Viewport.Y + viewPos.Y, 0, _document.LineCount - 1);
87→        DocumentLine line = _document.GetLineByNumber (lineIndex + 1);
88→        var col = Math.Max (0, Viewport.X + viewPos.X);
89→        var colInLine = GetLogicalColumnFromVisualColumn (line, col);
90→
91→        return line.Offset + colInLine;
92→    }
93→}
