  1→using Terminal.Gui.Text.Document;
  2→
  3→namespace Terminal.Gui.Views;
  4→
  5→/// <summary>
  6→///     Selection state and operations. Internal model is anchor + caret: <c>_selectionAnchor</c> is
  7→///     where Shift was first held; the <c>CaretOffset</c> is the live end. Selection is the segment
  8→///     between the two; when they coincide (or the anchor is null), there is no selection.
  9→/// </summary>
 10→public partial class Editor
 11→{
 12→    private int? _selectionAnchor;
 13→
 14→    /// <summary>True when there is a non-empty selection.</summary>
 15→    public bool HasSelection => _selectionAnchor is { } a && a != _caretOffset;
 16→
 17→    /// <summary>Start offset of the selection (inclusive). Equals <see cref="CaretOffset" /> when no selection.</summary>
 18→    public int SelectionStart => HasSelection ? Math.Min (_selectionAnchor!.Value, _caretOffset) : _caretOffset;
 19→
 20→    /// <summary>End offset of the selection (exclusive). Equals <see cref="CaretOffset" /> when no selection.</summary>
 21→    public int SelectionEnd => HasSelection ? Math.Max (_selectionAnchor!.Value, _caretOffset) : _caretOffset;
 22→
 23→    /// <summary>Length of the selection in characters; 0 when no selection.</summary>
 24→    public int SelectionLength => SelectionEnd - SelectionStart;
 25→
 26→    /// <summary>The selection as a <see cref="TextSegment" />, or <see langword="null" /> if no selection.</summary>
 27→    public TextSegment? Selection =>
 28→        !HasSelection ? null : new TextSegment { StartOffset = SelectionStart, Length = SelectionLength };
 29→
 30→    /// <summary>Raised whenever the selection range changes (created, extended, cleared).</summary>
 31→    public event EventHandler? SelectionChanged;
 32→
 33→    /// <summary>Clears the selection without moving the caret.</summary>
 34→    public void ClearSelection ()
 35→    {
 36→        if (_selectionAnchor is null)
 37→        {
 38→            return;
 39→        }
 40→
 41→        (int start, int end) before = SelectionTuple ();
 42→        _selectionAnchor = null;
 43→        RaiseSelectionChangedIfMoved (before);
 44→        SetNeedsDraw ();
 45→    }
 46→
 47→    /// <summary>Selects the entire document. Caret moves to <c>TextLength</c>.</summary>
 48→    public void SelectAll ()
 49→    {
 50→        (int start, int end) before = SelectionTuple ();
 51→        _selectionAnchor = 0;
 52→        CaretOffset = _document!.TextLength;
 53→        RaiseSelectionChangedIfMoved (before);
 54→        SetNeedsDraw ();
 55→    }
 56→
 57→    /// <summary>
 58→    ///     Replaces the current selection with <paramref name="replacement" />. If there is no selection, this is a no-op.
 59→    ///     The caret lands at <c>SelectionStart + replacement.Length</c> via the document's edit-tracking arithmetic.
 60→    /// </summary>
 61→    public void ReplaceSelection (string replacement)
 62→    {
 63→        if (!HasSelection)
 64→        {
 65→            return;
 66→        }
 67→
 68→        var start = SelectionStart;
 69→        var len = SelectionLength;
 70→
 71→        (int start, int end) before = SelectionTuple ();
 72→        _selectionAnchor = null;
 73→        _document!.Replace (start, len, replacement);
 74→        RaiseSelectionChangedIfMoved (before);
 75→    }
 76→
 77→    /// <summary>
 78→    ///     Begins (if needed) or extends the selection by setting the anchor to the current caret and then moving the
 79→    ///     caret <paramref name="delta" /> characters horizontally.
 80→    /// </summary>
 81→    private void ExtendCaretBy (int delta)
 82→    {
 83→        ExtendCaretTo (_caretOffset + delta);
 84→    }
 85→
 86→    private void ExtendCaretVertically (int delta)
 87→    {
 88→        (int start, int end) before = SelectionTupleWithEnsuredAnchor ();
 89→        MoveCaretVertically (delta);
 90→        RaiseSelectionChangedIfMoved (before);
 91→        SetNeedsDraw ();
 92→    }
 93→
 94→    private void ExtendCaretTo (int newCaret)
 95→    {
 96→        (int start, int end) before = SelectionTupleWithEnsuredAnchor ();
 97→        CaretOffset = newCaret;
 98→        RaiseSelectionChangedIfMoved (before);
 99→        SetNeedsDraw ();
100→    }
101→
102→    private void EnsureSelectionAnchor ()
103→    {
104→        _selectionAnchor ??= _caretOffset;
105→    }
106→
107→    /// <summary>
108→    ///     Returns the current effective selection range as a (start, end) tuple. Callers compare a
109→    ///     before-snapshot to the post-mutation tuple via <see cref="RaiseSelectionChangedIfMoved" /> to
110→    ///     suppress no-op <see cref="SelectionChanged" /> firings.
111→    /// </summary>
112→    private (int start, int end) SelectionTuple ()
113→    {
114→        return (SelectionStart, SelectionEnd);
115→    }
116→
117→    /// <summary>
118→    ///     Snapshot variant that primes the selection anchor first — used by extend-style operations
119→    ///     where setting the anchor is part of the operation but should not by itself count as a
120→    ///     selection-range change.
121→    /// </summary>
122→    private (int start, int end) SelectionTupleWithEnsuredAnchor ()
123→    {
124→        EnsureSelectionAnchor ();
125→
126→        return SelectionTuple ();
127→    }
128→
129→    private void RaiseSelectionChangedIfMoved ((int start, int end) before)
130→    {
131→        if (before == SelectionTuple ())
132→        {
133→            return;
134→        }
135→
136→        SelectionChanged?.Invoke (this, EventArgs.Empty);
137→    }
138→
139→    /// <summary>
140→    ///     Movement helper that respects an existing selection: plain (non-extending) cursor keys clear the selection
141→    ///     and snap to the appropriate end; otherwise the caret moves by <paramref name="delta" />.
142→    /// </summary>
143→    private void MoveCaretByCollapsingSelection (int delta)
144→    {
145→        if (HasSelection)
146→        {
147→            var target = delta < 0 ? SelectionStart : SelectionEnd;
148→            ClearSelection ();
149→            CaretOffset = target;
150→
151→            return;
152→        }
153→
154→        CaretOffset = _caretOffset + delta;
155→    }
156→
157→    /// <summary>
158→    ///     Vertical movement helper: clears any selection then runs the standard line-up/line-down with sticky-column.
159→    /// </summary>
160→    private void MoveCaretVerticallyCollapsingSelection (int delta)
161→    {
162→        ClearSelection ();
163→        MoveCaretVertically (delta);
164→    }
165→}
