  1→using Terminal.Gui.Input;
  2→using Terminal.Gui.Text.Document;
  3→using Terminal.Gui.ViewBase;
  4→
  5→namespace Terminal.Gui.Views;
  6→
  7→public partial class Editor
  8→{
  9→    /// <summary>
 10→    ///     Editor-specific default key bindings layered on top of <see cref="View.DefaultKeyBindings" />.
 11→    ///     The base layer already maps cursor / Home / End / PageUp / PageDown (and their Shift variants)
 12→    ///     to the corresponding movement and *Extend <see cref="Command" />s, plus Ctrl+A → SelectAll;
 13→    ///     this dictionary covers what's editor-specific (Enter, Backspace/Delete, Ctrl+Z / Ctrl+Y, the
 14→    ///     Ctrl+Home/End whole-document binds).
 15→    /// </summary>
 16→    /// <remarks>
 17→    ///     Process-wide static. Do not mutate from parallel tests — see Terminal.Gui's same convention
 18→    ///     on <see cref="Terminal.Gui.Views.TextField.DefaultKeyBindings" />.
 19→    /// </remarks>
 20→    public new static Dictionary<Command, PlatformKeyBinding>? DefaultKeyBindings { get; set; } = new ()
 21→    {
 22→        [Command.Start] = Bind.All (Key.Home.WithCtrl),
 23→        [Command.End] = Bind.All (Key.End.WithCtrl),
 24→        [Command.NewLine] = Bind.All (Key.Enter),
 25→        [Command.DeleteCharLeft] = Bind.All (Key.Backspace),
 26→        [Command.DeleteCharRight] = Bind.All (Key.Delete),
 27→        [Command.Undo] = Bind.All (Key.Z.WithCtrl),
 28→        [Command.Redo] = Bind.All (Key.Y.WithCtrl, Key.Z.WithCtrl.WithShift)
 29→    };
 30→
 31→    private void CreateCommandsAndBindings ()
 32→    {
 33→        // View's SetupKeyboard pre-binds Enter→Accept and Space→Activate. In a text editor those
 34→        // are the literal characters, so reclaim them before applying layered bindings.
 35→        KeyBindings.Remove (Key.Enter);
 36→        KeyBindings.Remove (Key.Space);
 37→
 38→        // Plain movement (collapses any existing selection)
 39→        AddCommand (Command.Left, () => MoveCaretByCollapsing (-1));
 40→        AddCommand (Command.Right, () => MoveCaretByCollapsing (1));
 41→        AddCommand (Command.Up, () => MoveCaretVerticallyCollapsing (-1));
 42→        AddCommand (Command.Down, () => MoveCaretVerticallyCollapsing (1));
 43→        AddCommand (Command.LeftStart, MoveCaretToLineStart);
 44→        AddCommand (Command.RightEnd, MoveCaretToLineEnd);
 45→        AddCommand (Command.Start, () => SetCaretAndReturnTrue (0));
 46→        AddCommand (Command.End, () => SetCaretAndReturnTrue (_document!.TextLength));
 47→        AddCommand (Command.PageUp, () => MoveCaretVerticallyCollapsing (-Math.Max (1, Viewport.Height)));
 48→        AddCommand (Command.PageDown, () => MoveCaretVerticallyCollapsing (Math.Max (1, Viewport.Height)));
 49→        AddCommand (Command.ScrollUp, () => ScrollVerticalCommand (-1));
 50→        AddCommand (Command.ScrollDown, () => ScrollVerticalCommand (1));
 51→        AddCommand (Command.ScrollLeft, () => ScrollHorizontalCommand (-1));
 52→        AddCommand (Command.ScrollRight, () => ScrollHorizontalCommand (1));
 53→
 54→        // Selection-extending movement
 55→        AddCommand (Command.LeftExtend, () => ExtendCommand (() => ExtendCaretBy (-1)));
 56→        AddCommand (Command.RightExtend, () => ExtendCommand (() => ExtendCaretBy (1)));
 57→        AddCommand (Command.UpExtend, () => ExtendCommand (() => ExtendCaretVertically (-1)));
 58→        AddCommand (Command.DownExtend, () => ExtendCommand (() => ExtendCaretVertically (1)));
 59→        AddCommand (Command.LeftStartExtend,
 60→            () => ExtendCommand (() => ExtendCaretTo (_document!.GetLineByOffset (_caretOffset).Offset)));
 61→
 62→        AddCommand (Command.RightEndExtend, () => ExtendCommand (() =>
 63→        {
 64→            DocumentLine line = _document!.GetLineByOffset (_caretOffset);
 65→            ExtendCaretTo (line.Offset + line.Length);
 66→        }));
 67→
 68→        AddCommand (Command.StartExtend, () => ExtendCommand (() => ExtendCaretTo (0)));
 69→        AddCommand (Command.EndExtend, () => ExtendCommand (() => ExtendCaretTo (_document!.TextLength)));
 70→        AddCommand (Command.PageUpExtend,
 71→            () => ExtendCommand (() => ExtendCaretVertically (-Math.Max (1, Viewport.Height))));
 72→        AddCommand (Command.PageDownExtend,
 73→            () => ExtendCommand (() => ExtendCaretVertically (Math.Max (1, Viewport.Height))));
 74→
 75→        // Selection ops
 76→        AddCommand (Command.SelectAll, () =>
 77→        {
 78→            SelectAll ();
 79→
 80→            return true;
 81→        });
 82→
 83→        // Editing — selection-aware
 84→        AddCommand (Command.NewLine, () => InsertOrReplace ("\n"));
 85→        AddCommand (Command.DeleteCharLeft, DeleteLeft);
 86→        AddCommand (Command.DeleteCharRight, DeleteRight);
 87→
 88→        // History
 89→        AddCommand (Command.Undo, () =>
 90→        {
 91→            if (_document!.UndoStack.CanUndo)
 92→            {
 93→                ClearSelection ();
 94→                _document!.UndoStack.Undo ();
 95→            }
 96→
 97→            return true;
 98→        });
 99→
100→        AddCommand (Command.Redo, () =>
101→        {
102→            if (_document!.UndoStack.CanRedo)
103→            {
104→                ClearSelection ();
105→                _document!.UndoStack.Redo ();
106→            }
107→
108→            return true;
109→        });
110→
111→        ApplyKeyBindings (View.DefaultKeyBindings, DefaultKeyBindings);
112→
113→        MouseBindings.Add (MouseFlags.WheeledUp, Command.ScrollUp);
114→        MouseBindings.Add (MouseFlags.WheeledDown, Command.ScrollDown);
115→        MouseBindings.Add (MouseFlags.WheeledLeft, Command.ScrollLeft);
116→        MouseBindings.Add (MouseFlags.WheeledRight, Command.ScrollRight);
117→    }
118→
119→    private bool? ExtendCommand (Action extend)
120→    {
121→        extend ();
122→
123→        return true;
124→    }
125→
126→    private bool? MoveCaretByCollapsing (int delta)
127→    {
128→        MoveCaretByCollapsingSelection (delta);
129→
130→        return true;
131→    }
132→
133→    private bool? MoveCaretVerticallyCollapsing (int delta)
134→    {
135→        MoveCaretVerticallyCollapsingSelection (delta);
136→
137→        return true;
138→    }
139→
140→    private bool? ScrollVerticalCommand (int delta)
141→    {
142→        if (_document is null || ScrollVertical (delta) != true)
143→        {
144→            return false;
145→        }
146→
147→        SetNeedsDraw ();
148→
149→        return true;
150→    }
151→
152→    private bool? ScrollHorizontalCommand (int delta)
153→    {
154→        if (_document is null || ScrollHorizontal (delta) != true)
155→        {
156→            return false;
157→        }
158→
159→        SetNeedsDraw ();
160→
161→        return true;
162→    }
163→
164→    private bool? InsertOrReplace (string text)
165→    {
166→        if (HasSelection)
167→        {
168→            ReplaceSelection (text);
169→        }
170→        else
171→        {
172→            _document!.Insert (_caretOffset, text);
173→        }
174→
175→        return true;
176→    }
177→
178→    private bool? DeleteLeft ()
179→    {
180→        if (HasSelection)
181→        {
182→            ReplaceSelection (string.Empty);
183→        }
184→        else if (_caretOffset > 0)
185→        {
186→            _document!.Remove (_caretOffset - 1, 1);
187→        }
188→
189→        return true;
190→    }
191→
192→    private bool? DeleteRight ()
193→    {
194→        if (HasSelection)
195→        {
196→            ReplaceSelection (string.Empty);
197→        }
198→        else if (_caretOffset < _document!.TextLength)
199→        {
200→            _document!.Remove (_caretOffset, 1);
201→        }
202→
203→        return true;
204→    }
205→
206→    private bool? SetCaretAndReturnTrue (int offset)
207→    {
208→        CaretOffset = offset;
209→
210→        return true;
211→    }
212→
213→    private bool? MoveCaretToLineStart ()
214→    {
215→        DocumentLine line = _document!.GetLineByOffset (_caretOffset);
216→        CaretOffset = line.Offset;
217→
218→        return true;
219→    }
220→
221→    private bool? MoveCaretToLineEnd ()
222→    {
223→        DocumentLine line = _document!.GetLineByOffset (_caretOffset);
224→        CaretOffset = line.Offset + line.Length;
225→
226→        return true;
227→    }
228→}
