  1→namespace Terminal.Gui.Views;
  2→
  3→public partial class Editor
  4→{
  5→    /// <summary>
  6→    ///     Finds the next match for <paramref name="searchText" /> starting at the current caret (or after the current
  7→    ///     selection) and selects it.
  8→    /// </summary>
  9→    /// <returns><see langword="true" /> when a match is found; otherwise <see langword="false" />.</returns>
 10→    public bool FindNext (string searchText, bool matchCase = false, bool wrapAround = true)
 11→    {
 12→        if (string.IsNullOrEmpty (searchText) || _document is null)
 13→        {
 14→            return false;
 15→        }
 16→
 17→        var startOffset = HasSelection ? SelectionEnd : _caretOffset;
 18→        var matchOffset = FindForwardOffset (searchText, startOffset, matchCase);
 19→
 20→        if (matchOffset < 0 && wrapAround && startOffset > 0)
 21→        {
 22→            matchOffset = FindForwardOffset (searchText, 0, matchCase);
 23→        }
 24→
 25→        if (matchOffset < 0)
 26→        {
 27→            return false;
 28→        }
 29→
 30→        SelectSearchMatch (matchOffset, searchText.Length);
 31→
 32→        return true;
 33→    }
 34→
 35→    /// <summary>
 36→    ///     Finds the previous match for <paramref name="searchText" /> before the current caret (or before the current
 37→    ///     selection start) and selects it.
 38→    /// </summary>
 39→    /// <returns><see langword="true" /> when a match is found; otherwise <see langword="false" />.</returns>
 40→    public bool FindPrevious (string searchText, bool matchCase = false, bool wrapAround = true)
 41→    {
 42→        if (string.IsNullOrEmpty (searchText) || _document is null || _document.TextLength == 0)
 43→        {
 44→            return false;
 45→        }
 46→
 47→        var startOffset = HasSelection ? SelectionStart - 1 : _caretOffset - 1;
 48→        var matchOffset = FindBackwardOffset (searchText, startOffset, matchCase);
 49→
 50→        if (matchOffset < 0 && wrapAround && startOffset < _document.TextLength - 1)
 51→        {
 52→            matchOffset = FindBackwardOffset (searchText, _document.TextLength - 1, matchCase);
 53→        }
 54→
 55→        if (matchOffset < 0)
 56→        {
 57→            return false;
 58→        }
 59→
 60→        SelectSearchMatch (matchOffset, searchText.Length);
 61→
 62→        return true;
 63→    }
 64→
 65→    /// <summary>
 66→    ///     Replaces the current match (if selected) or finds the next match and replaces it.
 67→    /// </summary>
 68→    /// <returns><see langword="true" /> when a replacement is made; otherwise <see langword="false" />.</returns>
 69→    public bool ReplaceNext (string searchText, string replacement, bool matchCase = false, bool wrapAround = true)
 70→    {
 71→        ArgumentNullException.ThrowIfNull (replacement);
 72→
 73→        if (string.IsNullOrEmpty (searchText) || _document is null)
 74→        {
 75→            return false;
 76→        }
 77→
 78→        if (!SelectionMatches (searchText, matchCase))
 79→        {
 80→            if (!FindNext (searchText, matchCase, wrapAround))
 81→            {
 82→                return false;
 83→            }
 84→        }
 85→
 86→        ReplaceSelection (replacement);
 87→
 88→        return true;
 89→    }
 90→
 91→    /// <summary>
 92→    ///     Replaces all matches of <paramref name="searchText" /> in the document.
 93→    /// </summary>
 94→    /// <returns>The number of replacements performed.</returns>
 95→    public int ReplaceAll (string searchText, string replacement, bool matchCase = false)
 96→    {
 97→        ArgumentNullException.ThrowIfNull (replacement);
 98→
 99→        if (string.IsNullOrEmpty (searchText) || _document is null)
100→        {
101→            return 0;
102→        }
103→
104→        var replacements = 0;
105→        var searchOffset = 0;
106→
107→        // Group every replacement into one undo step (R5). Without this, ReplaceAll on N
108→        // matches produces N separate undo entries, so undoing the operation requires N
109→        // Ctrl+Z presses — surprising and wrong. RunUpdate () increments BeginUpdate; the
110→        // using-disposal calls EndUpdate, which collapses the operation group.
111→        using IDisposable scope = _document.RunUpdate ();
112→
113→        while (searchOffset < _document.TextLength)
114→        {
115→            var matchOffset = FindForwardOffset (searchText, searchOffset, matchCase);
116→
117→            if (matchOffset < 0)
118→            {
119→                break;
120→            }
121→
122→            SelectSearchMatch (matchOffset, searchText.Length);
123→            ReplaceSelection (replacement);
124→
125→            searchOffset = matchOffset + replacement.Length;
126→            replacements++;
127→        }
128→
129→        return replacements;
130→    }
131→
132→    private int FindForwardOffset (string searchText, int startOffset, bool matchCase)
133→    {
134→        if (_document is null || startOffset < 0 || startOffset > _document.TextLength)
135→        {
136→            return -1;
137→        }
138→
139→        StringComparison comparison = matchCase ? StringComparison.Ordinal : StringComparison.OrdinalIgnoreCase;
140→
141→        return _document.Text.IndexOf (searchText, startOffset, comparison);
142→    }
143→
144→    private int FindBackwardOffset (string searchText, int startOffset, bool matchCase)
145→    {
146→        if (_document is null || _document.TextLength == 0 || startOffset < 0)
147→        {
148→            return -1;
149→        }
150→
151→        var clampedStart = Math.Clamp (startOffset, 0, _document.TextLength - 1);
152→        StringComparison comparison = matchCase ? StringComparison.Ordinal : StringComparison.OrdinalIgnoreCase;
153→
154→        return _document.Text.LastIndexOf (searchText, clampedStart, comparison);
155→    }
156→
157→    private bool SelectionMatches (string searchText, bool matchCase)
158→    {
159→        if (!HasSelection || _document is null || SelectionLength != searchText.Length)
160→        {
161→            return false;
162→        }
163→
164→        if (SelectionStart < 0 || SelectionLength < 0 || SelectionEnd > _document.TextLength)
165→        {
166→            return false;
167→        }
168→
169→        StringComparison comparison = matchCase ? StringComparison.Ordinal : StringComparison.OrdinalIgnoreCase;
170→
171→        return string.Compare (_document.Text, SelectionStart, searchText, 0, searchText.Length, comparison) == 0;
172→    }
173→
174→    private void SelectSearchMatch (int startOffset, int length)
175→    {
176→        if (_document is null || length <= 0)
177→        {
178→            return;
179→        }
180→
181→        var start = Math.Clamp (startOffset, 0, _document.TextLength);
182→        var end = Math.Clamp (start + length, start, _document.TextLength);
183→
184→        _selectionAnchor = start;
185→        CaretOffset = end;
186→        SelectionChanged?.Invoke (this, EventArgs.Empty);
187→        SetNeedsDraw ();
188→    }
189→}
