 12→/// <summary>
 13→///     Top-level <see cref="Window" /> for the <c>ted</c> demo. MenuBar at top,
 14→///     <see cref="Editor" /> in the middle, StatusBar at the bottom. Single-file —
 15→///     no tabs (compare to Terminal.Gui's Notepad scenario).
 16→/// </summary>
 17→public sealed class TedApp : Window
 18→{
 19→    private readonly Shortcut _fileNameShortcut;
 20→
 21→    /// <summary>Initializes a new <see cref="TedApp" />.</summary>
 22→    public TedApp ()
 23→    {
 24→        Title = "ted — Terminal.Gui.Editor demo";
 25→        BorderStyle = LineStyle.None;
 26→
 27→        // Editor first so menu/status-bar shortcuts can pull their hotkeys directly from
 28→        // Editor's KeyBindings (any commands the editor doesn't claim fall back to Application).
 29→        Editor = new Editor ();
 30→
 31→        // ted is the demo for the stopgap Editor.SyntaxHighlighter / SyntaxLanguage surface
