195→    /// <summary>Prompts for a file path, then loads that file into the editor.</summary>
196→    public bool OpenFile ()
197→    {
198→        var filePath = ShowOpenDialog ();
199→
200→        if (string.IsNullOrWhiteSpace (filePath))
201→        {
202→            return false;
203→        }
204→
205→        SetDocument (ReadAllText (filePath), filePath);
206→
207→        return true;
208→    }
209→
210→    /// <summary>Saves the editor text to the current file, or prompts for a path if the buffer is untitled.</summary>
211→    public bool SaveFile ()
212→    {
213→        if (CurrentFilePath is null)
214→        {
215→            return SaveFileAs ();
216→        }
217→
218→        WriteAllText (CurrentFilePath, GetEditorText ());
219→
220→        return true;
221→    }
222→
223→    /// <summary>Prompts for a file path, then saves the editor text to that path.</summary>
224→    public bool SaveFileAs ()
225→    {
226→        var filePath = ShowSaveDialog ();
227→
228→        if (string.IsNullOrWhiteSpace (filePath))
229→        {
230→            return false;
231→        }
232→
233→        CurrentFilePath = filePath;
234→        WriteAllText (filePath, GetEditorText ());
235→        UpdateFileNameShortcut ();
236→
237→        return true;
238→    }
