240→    /// <summary>
241→    ///     Resolves the key shortcut for <paramref name="command" /> by asking the <see cref="Editor" />'s
242→    ///     <see cref="View.KeyBindings" /> first; falls back to <see cref="Application.GetDefaultKey" /> for
243→    ///     commands the editor doesn't claim (Quit, Open/Save, clipboard, …).
244→    /// </summary>
245→    private Key KeyFor (Command command)
246→    {
247→        return Editor.KeyBindings.GetAllFromCommands (command).FirstOrDefault () ?? Application.GetDefaultKey (command);
248→    }
