 32→    /// <summary>
 33→    /// Specifies the mode for getting the next caret position.
 34→    /// </summary>
 35→    public enum CaretPositioningMode
 36→    {
 37→        /// <summary>
 38→        /// Normal positioning (stop after every grapheme)
 39→        /// </summary>
 40→        Normal,
 41→        /// <summary>
 42→        /// Stop only on word borders.
 43→        /// </summary>
 44→        WordBorder,
 45→        /// <summary>
 46→        /// Stop only at the beginning of words. This is used for Ctrl+Left/Ctrl+Right.
 47→        /// </summary>
 48→        WordStart,
 49→        /// <summary>
 50→        /// Stop only at the beginning of words, and anywhere in the middle of symbols.
 51→        /// </summary>
 52→        WordStartOrSymbol,
 53→        /// <summary>
 54→        /// Stop only on word borders, and anywhere in the middle of symbols.
 55→        /// </summary>
 56→        WordBorderOrSymbol,
 57→        /// <summary>
 58→        /// Stop between every Unicode codepoint, even within the same grapheme.
 59→        /// This is used to implement deleting the previous grapheme when Backspace is pressed.
 60→        /// </summary>
 61→        EveryCodepoint
 62→    }
