 64→    /// <summary>
 65→    /// Static helper methods for working with text.
 66→    /// </summary>
 67→    public static partial class TextUtilities
 68→    {
 69→        #region GetControlCharacterName
 70→        // the names of the first 32 ASCII characters = Unicode C0 block
 71→        private static readonly string[] C0Table = {
 72→            "NUL", "SOH", "STX", "ETX", "EOT", "ENQ", "ACK", "BEL", "BS", "HT",
 73→            "LF", "VT", "FF", "CR", "SO", "SI", "DLE", "DC1", "DC2", "DC3",
 74→            "DC4", "NAK", "SYN", "ETB", "CAN", "EM", "SUB", "ESC", "FS", "GS",
 75→            "RS", "US"
 76→        };
 77→
 78→        // DEL (ASCII 127) and
 79→        // the names of the control characters in the C1 block (Unicode 128 to 159)
 80→        private static readonly string[] DelAndC1Table = {
 81→            "DEL",
 82→            "PAD", "HOP", "BPH", "NBH", "IND", "NEL", "SSA", "ESA", "HTS", "HTJ",
 83→            "VTS", "PLD", "PLU", "RI", "SS2", "SS3", "DCS", "PU1", "PU2", "STS",
 84→            "CCH", "MW", "SPA", "EPA", "SOS", "SGCI", "SCI", "CSI", "ST", "OSC",
 85→            "PM", "APC"
 86→        };
 87→
 88→        /// <summary>
 89→        /// Gets the name of the control character.
 90→        /// For unknown characters, the unicode codepoint is returned as 4-digit hexadecimal value.
 91→        /// </summary>
 92→        public static string GetControlCharacterName(char controlCharacter)
 93→        {
 94→            int num = controlCharacter;
 95→            if (num < C0Table.Length)
 96→                return C0Table[num];
 97→            if (num >= 127 && num <= 159)
 98→                return DelAndC1Table[num - 127];
 99→            return num.ToString("x4", CultureInfo.InvariantCulture);
100→        }
101→        #endregion
102→
103→        #region GetWhitespace
104→        /// <summary>
105→        /// Gets all whitespace (' ' and '\t', but no newlines) after offset.
106→        /// </summary>
107→        /// <param name="textSource">The text source.</param>
108→        /// <param name="offset">The offset where the whitespace starts.</param>
109→        /// <returns>The segment containing the whitespace.</returns>
110→        [System.Diagnostics.CodeAnalysis.SuppressMessage("Microsoft.Naming", "CA1702:CompoundWordsShouldBeCasedCorrectly", MessageId = "Whitespace")]
111→        public static ISegment GetWhitespaceAfter(ITextSource textSource, int offset)
112→        {
113→            if (textSource == null)
114→                throw new ArgumentNullException(nameof(textSource));
115→            int pos;
116→            for (pos = offset; pos < textSource.TextLength; pos++)
117→            {
118→                char c = textSource.GetCharAt(pos);
119→                if (c != ' ' && c != '\t')
120→                    break;
121→            }
122→            return new SimpleSegment(offset, pos - offset);
123→        }
124→
125→        /// <summary>
126→        /// Gets all whitespace (' ' and '\t', but no newlines) before offset.
127→        /// </summary>
128→        /// <param name="textSource">The text source.</param>
129→        /// <param name="offset">The offset where the whitespace ends.</param>
130→        /// <returns>The segment containing the whitespace.</returns>
131→        [System.Diagnostics.CodeAnalysis.SuppressMessage("Microsoft.Naming", "CA1702:CompoundWordsShouldBeCasedCorrectly", MessageId = "Whitespace")]
132→        public static ISegment GetWhitespaceBefore(ITextSource textSource, int offset)
133→        {
134→            if (textSource == null)
135→                throw new ArgumentNullException(nameof(textSource));
136→            int pos;
137→            for (pos = offset - 1; pos >= 0; pos--)
138→            {
139→                char c = textSource.GetCharAt(pos);
140→                if (c != ' ' && c != '\t')
141→                    break;
142→            }
143→            pos++; // go back the one character that isn't whitespace
144→            return new SimpleSegment(pos, offset - pos);
145→        }
146→
147→        /// <summary>
148→        /// Gets the leading whitespace segment on the document line.
149→        /// </summary>
150→        [System.Diagnostics.CodeAnalysis.SuppressMessage("Microsoft.Naming", "CA1702:CompoundWordsShouldBeCasedCorrectly", MessageId = "Whitespace")]
151→        [System.Diagnostics.CodeAnalysis.SuppressMessage("Microsoft.Design", "CA1011:ConsiderPassingBaseTypesAsParameters",
152→                                                         Justification = "Parameter cannot be ITextSource because it must belong to the DocumentLine")]
153→        public static ISegment GetLeadingWhitespace(TextDocument document, DocumentLine documentLine)
154→        {
155→            if (documentLine == null)
156→                throw new ArgumentNullException(nameof(documentLine));
157→            return GetWhitespaceAfter(document, documentLine.Offset);
158→        }
159→
160→        /// <summary>
161→        /// Gets the trailing whitespace segment on the document line.
162→        /// </summary>
163→        [System.Diagnostics.CodeAnalysis.SuppressMessage("Microsoft.Naming", "CA1702:CompoundWordsShouldBeCasedCorrectly", MessageId = "Whitespace")]
164→        [System.Diagnostics.CodeAnalysis.SuppressMessage("Microsoft.Design", "CA1011:ConsiderPassingBaseTypesAsParameters",
165→                                                         Justification = "Parameter cannot be ITextSource because it must belong to the DocumentLine")]
166→        public static ISegment GetTrailingWhitespace(TextDocument document, DocumentLine documentLine)
167→        {
168→            if (documentLine == null)
169→                throw new ArgumentNullException(nameof(documentLine));
170→            ISegment segment = GetWhitespaceBefore(document, documentLine.EndOffset);
171→            // If the whole line consists of whitespace, we consider all of it as leading whitespace,
172→            // so return an empty segment as trailing whitespace.
173→            if (segment.Offset == documentLine.Offset)
174→                return new SimpleSegment(documentLine.EndOffset, 0);
175→            else
176→                return segment;
177→        }
178→        #endregion
179→
180→        #region GetSingleIndentationSegment
181→        /// <summary>
182→        /// Gets a single indentation segment starting at <paramref name="offset"/> - at most one tab
183→        /// or <paramref name="indentationSize"/> spaces.
184→        /// </summary>
185→        /// <param name="textSource">The text source.</param>
186→        /// <param name="offset">The offset where the indentation segment starts.</param>
187→        /// <param name="indentationSize">The size of an indentation unit. See <see cref="TextEditorOptions.IndentationSize"/>.</param>
188→        /// <returns>The indentation segment.
189→        /// If there is no indentation character at the specified <paramref name="offset"/>,
190→        /// an empty segment is returned.</returns>
191→        public static ISegment GetSingleIndentationSegment(ITextSource textSource, int offset, int indentationSize)
192→        {
193→            if (textSource == null)
194→                throw new ArgumentNullException(nameof(textSource));
195→            int pos = offset;
196→            while (pos < textSource.TextLength)
197→            {
198→                char c = textSource.GetCharAt(pos);
199→                if (c == '\t')
200→                {
201→                    if (pos == offset)
202→                        return new SimpleSegment(offset, 1);
203→                    else
204→                        break;
205→                }
206→                else if (c == ' ')
207→                {
208→                    if (pos - offset >= indentationSize)
209→                        break;
210→                }
211→                else
212→                {
213→                    break;
214→                }
215→                // continue only if c==' ' and (pos-offset)<tabSize
216→                pos++;
217→            }
218→            return new SimpleSegment(offset, pos - offset);
219→        }
220→        #endregion
221→
222→        #region GetCharacterClass
223→        /// <summary>
224→        /// Gets whether the character is whitespace, part of an identifier, or line terminator.
225→        /// </summary>
226→        [System.Diagnostics.CodeAnalysis.SuppressMessage("Microsoft.Naming", "CA1704:IdentifiersShouldBeSpelledCorrectly", MessageId = "c")]
227→        public static CharacterClass GetCharacterClass(char c)
228→        {
229→            if (c == '\r' || c == '\n')
230→                return CharacterClass.LineTerminator;
231→            if (c == '_')
232→                return CharacterClass.IdentifierPart;
233→            return GetCharacterClass(GetUnicodeCategory(c));
234→        }
235→
236→        private static CharacterClass GetCharacterClass(char highSurrogate, char lowSurrogate)
237→        {
238→            if (char.IsSurrogatePair(highSurrogate, lowSurrogate))
239→            {
240→                return GetCharacterClass(GetUnicodeCategoryString(highSurrogate.ToString() + lowSurrogate, 0));
241→            }
242→            // malformed surrogate pair
243→            return CharacterClass.Other;
244→        }
245→
246→        private static readonly Func<char, UnicodeCategory> GetUnicodeCategory = (Func<char, UnicodeCategory>)typeof(char)
247→            .GetRuntimeMethod("GetUnicodeCategory", new[] { typeof(char) })
248→            .CreateDelegate(typeof(Func<char, UnicodeCategory>));
249→
250→        private static readonly Func<string, int, UnicodeCategory> GetUnicodeCategoryString = (Func<string, int, UnicodeCategory>)typeof(char)
251→            .GetRuntimeMethod("GetUnicodeCategory", new[] { typeof(string), typeof(int) })
252→            .CreateDelegate(typeof(Func<string, int, UnicodeCategory>));
253→
254→        private static CharacterClass GetCharacterClass(UnicodeCategory c)
255→        {
256→            switch (c)
257→            {
258→                case UnicodeCategory.SpaceSeparator:
259→                case UnicodeCategory.LineSeparator:
260→                case UnicodeCategory.ParagraphSeparator:
261→                case UnicodeCategory.Control:
262→                    return CharacterClass.Whitespace;
263→                case UnicodeCategory.UppercaseLetter:
264→                case UnicodeCategory.LowercaseLetter:
265→                case UnicodeCategory.TitlecaseLetter:
266→                case UnicodeCategory.ModifierLetter:
267→                case UnicodeCategory.OtherLetter:
268→                case UnicodeCategory.DecimalDigitNumber:
269→                    return CharacterClass.IdentifierPart;
270→                case UnicodeCategory.NonSpacingMark:
271→                case UnicodeCategory.SpacingCombiningMark:
272→                case UnicodeCategory.EnclosingMark:
273→                    return CharacterClass.CombiningMark;
274→                default:
275→                    return CharacterClass.Other;
276→            }
277→        }
278→        #endregion
279→
280→        #region GetNextCaretPosition
281→        /// <summary>
282→        /// Gets the next caret position.
283→        /// </summary>
284→        /// <param name="textSource">The text source.</param>
285→        /// <param name="offset">The start offset inside the text source.</param>
286→        /// <param name="direction">The search direction (forwards or backwards).</param>
287→        /// <param name="mode">The mode for caret positioning.</param>
288→        /// <returns>The offset of the next caret position, or -1 if there is no further caret position
289→        /// in the text source.</returns>
290→        /// <remarks>
291→        /// This method is NOT equivalent to the actual caret movement when using VisualLine.GetNextCaretPosition.
292→        /// In real caret movement, there are additional caret stops at line starts and ends. This method
293→        /// treats linefeeds as simple whitespace.
294→        /// </remarks>
295→        public static int GetNextCaretPosition(ITextSource textSource, int offset, LogicalDirection direction, CaretPositioningMode mode)
296→        {
297→            if (textSource == null)
298→                throw new ArgumentNullException(nameof(textSource));
299→            switch (mode)
300→            {
301→                case CaretPositioningMode.Normal:
302→                case CaretPositioningMode.EveryCodepoint:
303→                case CaretPositioningMode.WordBorder:
304→                case CaretPositioningMode.WordBorderOrSymbol:
305→                case CaretPositioningMode.WordStart:
306→                case CaretPositioningMode.WordStartOrSymbol:
307→                    break; // OK
308→                default:
309→                    throw new ArgumentException("Unsupported CaretPositioningMode: " + mode, nameof(mode));
310→            }
311→            if (direction != LogicalDirection.Backward
312→                && direction != LogicalDirection.Forward)
313→            {
314→                throw new ArgumentException("Invalid LogicalDirection: " + direction, nameof(direction));
315→            }
316→            int textLength = textSource.TextLength;
317→            if (textLength <= 0)
318→            {
319→                // empty document? has a normal caret position at 0, though no word borders
320→                if (IsNormal(mode))
321→                {
322→                    if (offset > 0 && direction == LogicalDirection.Backward) return 0;
323→                    if (offset < 0 && direction == LogicalDirection.Forward) return 0;
324→                }
325→                return -1;
326→            }
327→            while (true)
328→            {
329→                int nextPos = (direction == LogicalDirection.Backward) ? offset - 1 : offset + 1;
330→
331→                // return -1 if there is no further caret position in the text source
332→                // we also need this to handle offset values outside the valid range
333→                if (nextPos < 0 || nextPos > textLength)
334→                    return -1;
335→
336→                // check if we've run against the textSource borders.
337→                // a 'textSource' usually isn't the whole document, but a single VisualLineElement.
338→                if (nextPos == 0)
339→                {
340→                    // at the document start, there's only a word border
341→                    // if the first character is not whitespace
342→                    if (IsNormal(mode) || !char.IsWhiteSpace(textSource.GetCharAt(0)))
343→                        return nextPos;
344→                }
345→                else if (nextPos == textLength)
346→                {
347→                    // at the document end, there's never a word start
348→                    if (mode != CaretPositioningMode.WordStart && mode != CaretPositioningMode.WordStartOrSymbol)
349→                    {
350→                        // at the document end, there's only a word border
351→                        // if the last character is not whitespace
352→                        if (IsNormal(mode) || !char.IsWhiteSpace(textSource.GetCharAt(textLength - 1)))
353→                            return nextPos;
354→                    }
355→                }
356→                else
357→                {
358→                    char charBefore = textSource.GetCharAt(nextPos - 1);
359→                    char charAfter = textSource.GetCharAt(nextPos);
360→                    // Don't stop in the middle of a surrogate pair
361→                    if (!char.IsSurrogatePair(charBefore, charAfter))
362→                    {
363→                        CharacterClass classBefore = GetCharacterClass(charBefore);
364→                        CharacterClass classAfter = GetCharacterClass(charAfter);
365→                        // get correct class for characters outside BMP:
366→                        if (char.IsLowSurrogate(charBefore) && nextPos >= 2)
367→                        {
368→                            classBefore = GetCharacterClass(textSource.GetCharAt(nextPos - 2), charBefore);
369→                        }
370→                        if (char.IsHighSurrogate(charAfter) && nextPos + 1 < textLength)
371→                        {
372→                            classAfter = GetCharacterClass(charAfter, textSource.GetCharAt(nextPos + 1));
373→                        }
374→                        if (StopBetweenCharacters(mode, classBefore, classAfter))
375→                        {
376→                            return nextPos;
377→                        }
378→                    }
379→                }
380→                // we'll have to continue searching...
381→                offset = nextPos;
382→            }
383→        }
384→
385→        private static bool IsNormal(CaretPositioningMode mode)
386→        {
387→            return mode == CaretPositioningMode.Normal || mode == CaretPositioningMode.EveryCodepoint;
388→        }
389→
390→        private static bool StopBetweenCharacters(CaretPositioningMode mode, CharacterClass charBefore, CharacterClass charAfter)
391→        {
392→            if (mode == CaretPositioningMode.EveryCodepoint)
393→                return true;
394→            // Don't stop in the middle of a grapheme
395→            if (charAfter == CharacterClass.CombiningMark)
396→                return false;
397→            // Stop after every grapheme in normal mode
398→            if (mode == CaretPositioningMode.Normal)
399→                return true;
400→            if (charBefore == charAfter)
401→            {
402→                if (charBefore == CharacterClass.Other &&
403→                    (mode == CaretPositioningMode.WordBorderOrSymbol || mode == CaretPositioningMode.WordStartOrSymbol))
404→                {
405→                    // With the "OrSymbol" modes, there's a word border and start between any two unknown characters
406→                    return true;
407→                }
408→            }
409→            else
410→            {
411→                // this looks like a possible border
412→
413→                // if we're looking for word starts, check that this is a word start (and not a word end)
414→                // if we're just checking for word borders, accept unconditionally
415→                if (!((mode == CaretPositioningMode.WordStart || mode == CaretPositioningMode.WordStartOrSymbol)
416→                      && (charAfter == CharacterClass.Whitespace || charAfter == CharacterClass.LineTerminator)))
417→                {
418→                    return true;
419→                }
420→            }
421→            return false;
422→        }
423→        #endregion
424→    }
425→
426→    /// <summary>
427→    /// Classifies a character as whitespace, line terminator, part of an identifier, or other.
428→    /// </summary>
429→    public enum CharacterClass
430→    {
431→        /// <summary>
432→        /// The character is not whitespace, line terminator or part of an identifier.
433→        /// </summary>
434→        Other,
435→        /// <summary>
436→        /// The character is whitespace (but not line terminator).
437→        /// </summary>
438→        [System.Diagnostics.CodeAnalysis.SuppressMessage("Microsoft.Naming", "CA1702:CompoundWordsShouldBeCasedCorrectly", MessageId = "Whitespace")]
439→        Whitespace,
440→        /// <summary>
441→        /// The character can be part of an identifier (Letter, digit or underscore).
442→        /// </summary>
443→        IdentifierPart,
444→        /// <summary>
445→        /// The character is line terminator (\r or \n).
446→        /// </summary>
447→        LineTerminator,
448→        /// <summary>
449→        /// The character is a unicode combining mark that modifies the previous character.
450→        /// Corresponds to the Unicode designations "Mn", "Mc" and "Me".
451→        /// </summary>
452→        CombiningMark
453→    }
454→}
