251→    private void UpdateContentSize ()
252→    {
253→        if (_document == null)
254→        {
255→            return;
256→        }
257→
258→        var maxWidth = _document.Lines.Select (line => GetVisualColumnFromLogicalColumn (line, line.Length)).Prepend (0)
259→            .Max ();
260→
261→        // +1 column lets the caret sit just past the end-of-line.
262→        SetContentSize (new (maxWidth + 1, _document.LineCount));
263→    }
264→
265→    private void UpdateLineNumberPadding ()
266→    {
267→        Thickness thickness = Padding.Thickness;
268→        var left = _showLineNumbers && _document is not null ? GetLineNumberPaddingWidth () : 0;
269→
270→        if (thickness.Left == left)
271→        {
272→            return;
273→        }
274→
275→        Padding.Thickness = new (left, thickness.Top, thickness.Right, thickness.Bottom);
276→    }
277→
278→    private int GetLineNumberPaddingWidth ()
279→    {
280→        var lineCount = Math.Max (1, _document?.LineCount ?? 1);
281→
282→        return lineCount.ToString ().Length + 1;
283→    }
284→
285→    private int GetCaretColumn ()
286→    {
287→        DocumentLine? line = _document?.GetLineByOffset (_caretOffset);
288→
289→        if (line is null)
290→        {
291→            return 0;
292→        }
293→
294→        var logicalColumn = _caretOffset - line.Offset;
295→
296→        return GetVisualColumnFromLogicalColumn (line, logicalColumn);
297→    }
298→
299→    private int GetCaretLineIndex ()
300→    {
301→        return _document?.GetLineByOffset (_caretOffset).LineNumber - 1 ?? 0;
302→    }
303→
304→    /// <summary>
305→    ///     Moves the caret <paramref name="delta" /> lines, preserving the sticky virtual column when
306→    ///     traversing shorter lines (i.e. snap back to the original column on the next long-enough line).
307→    /// </summary>
308→    private void MoveCaretVertically (int delta)
309→    {
310→        var targetLine = Math.Clamp (GetCaretLineIndex () + delta, 0, _document!.LineCount - 1);
311→        DocumentLine line = _document!.GetLineByNumber (targetLine + 1);
312→        var targetCol = GetLogicalColumnFromVisualColumn (line, _virtualCaretColumn);
313→
314→        // resetVirtualColumn: false keeps the sticky column intact across vertical moves.
315→        SetCaretOffset (line.Offset + targetCol, false);
316→    }
317→
318→    private int GetVisualColumnFromLogicalColumn (DocumentLine line, int logicalColumn)
319→    {
320→        var text = _document!.GetText (line);
321→        var clampedLogical = Math.Clamp (logicalColumn, 0, text.Length);
322→        var visualColumn = 0;
323→
324→        for (var i = 0; i < clampedLogical; i++)
325→        {
326→            visualColumn += GetVisualWidthForCharacter (text[i], visualColumn, TabWidth);
327→        }
328→
329→        return visualColumn;
330→    }
331→
332→    private int GetLogicalColumnFromVisualColumn (DocumentLine line, int visualColumn)
333→    {
334→        var text = _document!.GetText (line);
335→        var clampedVisual = Math.Max (0, visualColumn);
336→        var currentVisual = 0;
337→
338→        for (var logical = 0; logical < text.Length; logical++)
339→        {
340→            var width = GetVisualWidthForCharacter (text[logical], currentVisual, TabWidth);
341→            var nextVisual = currentVisual + width;
342→
343→            if (nextVisual >= clampedVisual)
344→            {
345→                if (text[logical] == '\t' && clampedVisual > currentVisual)
346→                {
347→                    // Clicking or moving inside the visual span produced by '\t' snaps the caret
348→                    // after the tab character because there is no representable position "inside"
349→                    // a single tab code point.
350→                    return logical + 1;
351→                }
352→
353→                return clampedVisual >= nextVisual ? logical + 1 : logical;
354→            }
355→
356→            currentVisual = nextVisual;
357→        }
358→
359→        return text.Length;
360→    }
361→
362→    private static int GetVisualWidthForCharacter (char c, int visualColumn, int tabWidth)
363→    {
364→        if (c != '\t')
365→        {
366→            return 1;
367→        }
368→
369→        var remainder = visualColumn % tabWidth;
370→
371→        return remainder == 0 ? tabWidth : tabWidth - remainder;
372→    }
373→
374→    private void EnsureCaretVisible ()
375→    {
376→        Rectangle viewport = Viewport;
377→
378→        if (viewport.Width == 0 || viewport.Height == 0)
379→        {
380→            return;
381→        }
382→
383→        var caretLine = GetCaretLineIndex ();
384→        var caretCol = GetCaretColumn ();
385→        var newY = viewport.Y;
386→        var newX = viewport.X;
387→
388→        if (caretLine < newY)
389→        {
390→            newY = caretLine;
391→        }
392→        else if (caretLine >= newY + viewport.Height)
393→        {
394→            newY = caretLine - viewport.Height + 1;
395→        }
396→
397→        if (caretCol < newX)
398→        {
399→            newX = caretCol;
400→        }
401→        else if (caretCol >= newX + viewport.Width)
402→        {
403→            newX = caretCol - viewport.Width + 1;
404→        }
405→
406→        if (newX != viewport.X || newY != viewport.Y)
407→        {
408→            Viewport = viewport with { X = newX, Y = newY };
409→        }
410→    }
411→}
