  2→using Terminal.Gui.Text.Document;
  3→using Terminal.Gui.ViewBase;
  4→
  5→namespace Terminal.Gui.Views;
  6→
  7→public partial class Editor
  8→{
  9→    /// <summary>
 10→    ///     Editor-specific default key bindings layered on top of <see cref="View.DefaultKeyBindings" />.
 11→    ///     The base layer already maps cursor / Home / End / PageUp / PageDown (and their Shift variants)
 12→    ///     to the corresponding movement and *Extend <see cref="Command" />s, plus Ctrl+A → SelectAll;
 13→    ///     this dictionary covers what's editor-specific (Enter, Backspace/Delete, Ctrl+Z / Ctrl+Y, the
 14→    ///     Ctrl+Home/End whole-document binds).
 15→    /// </summary>
 16→    /// <remarks>
 17→    ///     Process-wide static. Do not mutate from parallel tests — see Terminal.Gui's same convention
 18→    ///     on <see cref="Terminal.Gui.Views.TextField.DefaultKeyBindings" />.
 19→    /// </remarks>
 20→    public new static Dictionary<Command, PlatformKeyBinding>? DefaultKeyBindings { get; set; } = new ()
 21→    {
 22→        [Command.Start] = Bind.All (Key.Home.WithCtrl),
 23→        [Command.End] = Bind.All (Key.End.WithCtrl),
 24→        [Command.NewLine] = Bind.All (Key.Enter),
 25→        [Command.DeleteCharLeft] = Bind.All (Key.Backspace),
 26→        [Command.DeleteCharRight] = Bind.All (Key.Delete),
 27→        [Command.Undo] = Bind.All (Key.Z.WithCtrl),
 28→        [Command.Redo] = Bind.All (Key.Y.WithCtrl, Key.Z.WithCtrl.WithShift)
 29→    };
 30→
 31→    private void CreateCommandsAndBindings ()
 32→    {
 33→        // View's SetupKeyboard pre-binds Enter→Accept and Space→Activate. In a text editor those
 34→        // are the literal characters, so reclaim them before applying layered bindings.
 35→        KeyBindings.Remove (Key.Enter);
 36→        KeyBindings.Remove (Key.Space);
 37→
 38→        // Plain movement (collapses any existing selection)
 39→        AddCommand (Command.Left, () => MoveCaretByCollapsing (-1));
 40→        AddCommand (Command.Right, () => MoveCaretByCollapsing (1));
 41→        AddCommand (Command.Up, () => MoveCaretVerticallyCollapsing (-1));
 42→        AddCommand (Command.Down, () => MoveCaretVerticallyCollapsing (1));
 43→        AddCommand (Command.LeftStart, MoveCaretToLineStart);
 44→        AddCommand (Command.RightEnd, MoveCaretToLineEnd);
 45→        AddCommand (Command.Start, () => SetCaretAndReturnTrue (0));
 46→        AddCommand (Command.End, () => SetCaretAndReturnTrue (_document!.TextLength));
 47→        AddCommand (Command.PageUp, () => MoveCaretVerticallyCollapsing (-Math.Max (1, Viewport.Height)));
 48→        AddCommand (Command.PageDown, () => MoveCaretVerticallyCollapsing (Math.Max (1, Viewport.Height)));
 49→        AddCommand (Command.ScrollUp, () => ScrollVerticalCommand (-1));
 50→        AddCommand (Command.ScrollDown, () => ScrollVerticalCommand (1));
 51→        AddCommand (Command.ScrollLeft, () => ScrollHorizontalCommand (-1));
 52→        AddCommand (Command.ScrollRight, () => ScrollHorizontalCommand (1));
 53→
 54→        // Selection-extending movement
 55→        AddCommand (Command.LeftExtend, () => ExtendCommand (() => ExtendCaretBy (-1)));
 56→        AddCommand (Command.RightExtend, () => ExtendCommand (() => ExtendCaretBy (1)));
 57→        AddCommand (Command.UpExtend, () => ExtendCommand (() => ExtendCaretVertically (-1)));
 58→        AddCommand (Command.DownExtend, () => ExtendCommand (() => ExtendCaretVertically (1)));
 59→        AddCommand (Command.LeftStartExtend,
 60→            () => ExtendCommand (() => ExtendCaretTo (_document!.GetLineByOffset (_caretOffset).Offset)));
 61→
