 13→/// <summary>
 14→///     Asserts the visual roles used by <see cref="Views.Editor" /> when rendering. Unselected text
 15→///     should blend into the surrounding container (<see cref="VisualRole.Normal" />) — not
 16→///     <see cref="VisualRole.Editable" />, which is the dim/contrast role intended for input
 17→///     widgets like <see cref="Terminal.Gui.Views.TextField" /> and
 18→///     <see cref="Terminal.Gui.Views.TextView" />. Selected text uses
 19→///     <see cref="VisualRole.Active" />.
 20→/// </summary>
 21→public class EditorRenderingTests
 22→{
 23→    private static readonly InputInjectionOptions Direct = new () { Mode = InputInjectionMode.Direct };
 24→
 25→    [Fact]
 26→    public async Task Unselected_Text_Uses_Normal_Role_Not_Editable ()
 27→    {
 28→        await using AppFixture<EditorTestHost> fx = new (() => new ("Hello"));
 29→        fx.Render ();
 30→
 31→        Attribute normal = fx.Top.Editor.GetAttributeForRole (VisualRole.Normal);
 32→        Attribute editable = fx.Top.Editor.GetAttributeForRole (VisualRole.Editable);
 33→
 34→        // Precondition: this test is only meaningful if Normal and Editable differ in the
 35→        // active scheme. If they don't, the visual bug can't manifest and the assertion below
 36→        // would pass spuriously.
 37→        Assert.NotEqual (normal, editable);
 38→
 39→        Cell cell = fx.Driver.Contents![0, 0];
 40→        Assert.Equal ("H", cell.Grapheme);
 41→        Assert.Equal (normal, cell.Attribute);
 42→    }
 43→
 44→    [Fact]
 45→    public async Task Selected_Text_Uses_Active_Role ()
 46→    {
 47→        await using AppFixture<EditorTestHost> fx = new (() => new ("Hello"));
 48→        fx.Top.Editor.SetFocus ();
 49→        fx.Top.Editor.CaretOffset = 0;
 50→
 51→        fx.Injector.InjectKey (Key.CursorRight.WithShift, Direct);
 52→        fx.Injector.InjectKey (Key.CursorRight.WithShift, Direct);
 53→        fx.Render ();
 54→
 55→        Attribute active = fx.Top.Editor.GetAttributeForRole (VisualRole.Active);
 56→
 57→        Cell cellSelected = fx.Driver.Contents![0, 0];
 58→        Assert.Equal ("H", cellSelected.Grapheme);
 59→        Assert.Equal (active, cellSelected.Attribute);
 60→    }
 61→
 62→    [Fact]
 63→    public async Task Unselected_Tail_After_Selection_Uses_Normal_Role ()
 64→    {
 65→        await using AppFixture<EditorTestHost> fx = new (() => new ("Hello"));
 66→        fx.Top.Editor.SetFocus ();
 67→        fx.Top.Editor.CaretOffset = 0;
 68→
 69→        fx.Injector.InjectKey (Key.CursorRight.WithShift, Direct);
 70→        fx.Injector.InjectKey (Key.CursorRight.WithShift, Direct);
 71→        fx.Render ();
 72→
 73→        Attribute normal = fx.Top.Editor.GetAttributeForRole (VisualRole.Normal);
 74→        Attribute editable = fx.Top.Editor.GetAttributeForRole (VisualRole.Editable);
 75→        Assert.NotEqual (normal, editable);
 76→
 77→        // Cells past the selection (column index >= 2) should be Normal, not Editable.
 78→        Cell tail = fx.Driver.Contents![0, 2];
 79→        Assert.Equal ("l", tail.Grapheme);
 80→        Assert.Equal (normal, tail.Attribute);
 81→    }
 82→
 83→    [Fact]
 84→    public async Task LineNumbers_Render_In_LeftPadding ()
 85→    {
 86→        await using AppFixture<EditorTestHost> fx = new (() =>
 87→        {
 88→            EditorTestHost host = new ("alpha\nbeta");
 89→            host.Editor.ShowLineNumbers = true;
