 33→        fx.Injector.InjectKey (Key.H, Direct);
 34→        fx.Injector.InjectKey (Key.I, Direct);
 35→
 36→        // Bare letter keys produce lowercase; Shift would uppercase.
 37→        Assert.Equal ("hi", fx.Top.Editor.Document?.Text);
 38→        Assert.Equal (2, fx.Top.Editor.CaretOffset);
 39→    }
