 41→    [Fact]
 42→    public async Task CursorLeft_Right_MovesCaret ()
 43→    {
 44→        await using AppFixture<EditorTestHost> fx = new (() => new ("abc"));
 45→        fx.Top.Editor.SetFocus ();
 46→        fx.Top.Editor.CaretOffset = 3;
 47→
 48→        fx.Injector.InjectKey (Key.CursorLeft, Direct);
 49→        Assert.Equal (2, fx.Top.Editor.CaretOffset);
 50→
 51→        fx.Injector.InjectKey (Key.CursorLeft, Direct);
 52→        fx.Injector.InjectKey (Key.CursorLeft, Direct);
 53→        Assert.Equal (0, fx.Top.Editor.CaretOffset);
 54→
 55→        // Past start should clamp.
 56→        fx.Injector.InjectKey (Key.CursorLeft, Direct);
 57→        Assert.Equal (0, fx.Top.Editor.CaretOffset);
 58→
 59→        fx.Injector.InjectKey (Key.CursorRight, Direct);
 60→        Assert.Equal (1, fx.Top.Editor.CaretOffset);
 61→    }
 62→
 63→    [Fact]
 64→    public async Task CursorUp_Down_PreservesVirtualColumn_AcrossShortLines ()
 65→    {
 66→        await using AppFixture<EditorTestHost> fx = new (() => new ("longer line\nshort\nanother long line"));
 67→        fx.Top.Editor.SetFocus ();
 68→        fx.Top.Editor.CaretOffset = 8; // column 8 of "longer line"
 69→
 70→        fx.Injector.InjectKey (Key.CursorDown, Direct);
 71→
 72→        // "short" only has 5 chars — caret snaps to its end.
 73→        var afterFirstDown = fx.Top.Editor.CaretOffset;
 74→        Assert.Equal ("longer line\nshort".Length, afterFirstDown);
 75→
 76→        fx.Injector.InjectKey (Key.CursorDown, Direct);
 77→
 78→        // On the long line below, the sticky column 8 should be restored.
 79→        var afterSecondDown = fx.Top.Editor.CaretOffset;
 80→        var line3Start = "longer line\nshort\n".Length;
 81→        Assert.Equal (line3Start + 8, afterSecondDown);
 82→    }
 83→
 84→    [Fact]
 85→    public async Task CursorUp_Down_PreservesVirtualColumn_Across_Tab_Line ()
 86→    {
 87→        await using AppFixture<EditorTestHost> fx = new (() => new ("abcde\n\t\nabcde"));
 88→        fx.Top.Editor.SetFocus ();
 89→        fx.Top.Editor.CaretOffset = 3;
 90→
 91→        fx.Injector.InjectKey (Key.CursorDown, Direct);
 92→
 93→        int afterFirstDown = fx.Top.Editor.CaretOffset;
 94→        Assert.Equal ("abcde\n\t".Length, afterFirstDown);
 95→
 96→        fx.Injector.InjectKey (Key.CursorDown, Direct);
 97→
 98→        int afterSecondDown = fx.Top.Editor.CaretOffset;
 99→        int line3Start = "abcde\n\t\n".Length;
100→        Assert.Equal (line3Start + 3, afterSecondDown);
101→    }
102→
103→    [Fact]
104→    public async Task CursorDown_PreservesVirtualColumn_AcrossThreeIntermediateShortLines ()
105→    {
106→        // Regression guard for MoveCaretVertically's sticky-column path: the virtual column
107→        // must survive THREE consecutive snaps (short, empty, short) before snapping back on
108→        // the long line at the bottom.
109→        const string LongTop = "0123456789ABCDEF"; // 16 chars
110→        const string Short1 = "abc";
111→        const string Empty = "";
112→        const string Short2 = "xy";
113→        const string LongBottom = "0123456789ABCDEF";
114→
115→        string text = string.Join ("\n", LongTop, Short1, Empty, Short2, LongBottom);
116→
117→        await using AppFixture<EditorTestHost> fx = new (() => new (text));
118→        fx.Top.Editor.SetFocus ();
119→        fx.Top.Editor.CaretOffset = 12; // column 12 on the top long line
120→
121→        fx.Injector.InjectKey (Key.CursorDown, Direct);
122→        int afterDown1 = fx.Top.Editor.CaretOffset;
123→        Assert.Equal ((LongTop + "\n" + Short1).Length, afterDown1); // snaps to end of "abc"
124→
125→        fx.Injector.InjectKey (Key.CursorDown, Direct);
126→        int afterDown2 = fx.Top.Editor.CaretOffset;
127→        Assert.Equal ((LongTop + "\n" + Short1 + "\n").Length, afterDown2); // empty line, col 0
128→
129→        fx.Injector.InjectKey (Key.CursorDown, Direct);
130→        int afterDown3 = fx.Top.Editor.CaretOffset;
131→        Assert.Equal ((LongTop + "\n" + Short1 + "\n" + Empty + "\n" + Short2).Length, afterDown3); // end of "xy"
132→
