    } = 4;

    /// <summary>
    ///     When <see langword="true" />, pressing Tab inserts spaces (up to the next tab stop) instead
    ///     of a literal <c>\t</c>. Does not affect existing document content — only governs what
    ///     the Tab key inserts. Mirrors AvaloniaEdit's <c>TextEditorOptions.ConvertTabsToSpaces</c>.
    /// </summary>
    public bool ConvertTabsToSpaces { get; set; }

    /// <summary>
    ///     When <see langword="true" />, renders a tab glyph (<c>→</c>) in the first cell of each
    ///     tab expansion, padding the remaining cells with spaces. When <see langword="false" />,
    ///     tabs render as plain spaces. Mirrors AvaloniaEdit's <c>TextEditorOptions.ShowTabs</c>.
    /// </summary>
    public bool ShowTabs
    {
        get;
        set
        {
            if (field == value)
            {
                return;
            }

            field = value;
            SetNeedsDraw ();
        }
    }

    /// <summary>Raised whenever <see cref="CaretOffset" /> changes.</summary>
    public event EventHandler? CaretChanged;

    private void SetCaretOffset (int value, bool resetVirtualColumn)
    {
        var clamped = Math.Clamp (value, 0, _document?.TextLength ?? 0);

        if (clamped == _caretOffset && !resetVirtualColumn)
        {
            return;
        }

        var changed = clamped != _caretOffset;
        _caretOffset = clamped;

        if (resetVirtualColumn)
        {
            _virtualCaretColumn = GetCaretColumn ();
        }

        EnsureCaretVisible ();
        SetNeedsDraw ();

        if (changed)
        {
            CaretChanged?.Invoke (this, EventArgs.Empty);
        }
    }

    /// <inheritdoc />
    protected override void Dispose (bool disposing)
    {
        if (disposing && _document is not null)
        {
            // Without this the document keeps the editor alive via the Changed subscription whenever
            // external code retains the TextDocument (test fixtures, future shared docs across panes,
            // etc.). The Document setter unsubscribes on swap; this covers View-teardown.
            _document.Changed -= OnDocumentChanged;
        }

        base.Dispose (disposing);
    }

    private void OnDocumentChanged (object? sender, DocumentChangeEventArgs e)
    {
        // Content-size has to refresh first so EnsureCaretVisible inside SetCaretOffset clamps the
        // viewport against the new line count.
        UpdateContentSize ();

        // Manual stand-in for TextAnchor.AfterInsertion until specs/00-plan.md §6 lands. The math:
        // an insert at-or-before the caret pushes it forward by InsertionLength; an insert strictly
        // after the caret leaves it alone; a removal that straddles the caret snaps it to the
        // removal start; a removal entirely before the caret slides it back by RemovalLength.
        if (_caretOffset >= e.Offset)
        {
            var target = _caretOffset < e.Offset + e.RemovalLength
                ? e.Offset
                : _caretOffset - e.RemovalLength + e.InsertionLength;

            // Route through SetCaretOffset so CaretChanged fires when the caret actually moves.
            // SetCaretOffset also handles EnsureCaretVisible + SetNeedsDraw.
            SetCaretOffset (target, true);

            return;
        }

        UpdateContentSize ();
        UpdateLineNumberPadding ();
        EnsureCaretVisible ();
        SetNeedsDraw ();
    }

    private void UpdateContentSize ()
    {
        if (_document == null)
        {
            return;
        }

        var maxWidth = _document.Lines.Select (line => GetVisualColumnFromLogicalColumn (line, line.Length)).Prepend (0)
            .Max ();

        // +1 column lets the caret sit just past the end-of-line.
        SetContentSize (new (maxWidth + 1, _document.LineCount));
    }

    private void UpdateLineNumberPadding ()
    {
        Thickness thickness = Padding.Thickness;
        var left = _showLineNumbers && _document is not null ? GetLineNumberPaddingWidth () : 0;

        if (thickness.Left == left)
        {
            return;
        }

        Padding.Thickness = new (left, thickness.Top, thickness.Right, thickness.Bottom);
    }

    private int GetLineNumberPaddingWidth ()
    {
        var lineCount = Math.Max (1, _document?.LineCount ?? 1);

        return lineCount.ToString ().Length + 1;
    }

    private int GetCaretColumn ()
    {
        DocumentLine? line = _document?.GetLineByOffset (_caretOffset);

        if (line is null)
        {
            return 0;
        }

        var logicalColumn = _caretOffset - line.Offset;

        return GetVisualColumnFromLogicalColumn (line, logicalColumn);
    }

    private int GetCaretLineIndex ()
    {
        return _document?.GetLineByOffset (_caretOffset).LineNumber - 1 ?? 0;
    }

    /// <summary>
    ///     Moves the caret <paramref name="delta" /> lines, preserving the sticky virtual column when
    ///     traversing shorter lines (i.e. snap back to the original column on the next long-enough line).
    /// </summary>
    private void MoveCaretVertically (int delta)
    {
        var targetLine = Math.Clamp (GetCaretLineIndex () + delta, 0, _document!.LineCount - 1);
        DocumentLine line = _document!.GetLineByNumber (targetLine + 1);
        var targetCol = GetLogicalColumnFromVisualColumn (line, _virtualCaretColumn);

        // resetVirtualColumn: false keeps the sticky column intact across vertical moves.
        SetCaretOffset (line.Offset + targetCol, false);
    }

    // TODO(VisualLineBuilder): replace with CellVisualLine.GetVisualColumn once B1 lands.
    private int GetVisualColumnFromLogicalColumn (DocumentLine line, int logicalColumn)
    {
        var text = _document!.GetText (line);
        var clampedLogical = Math.Clamp (logicalColumn, 0, text.Length);
        var visualColumn = 0;

        for (var i = 0; i < clampedLogical; i++)
        {
            visualColumn += GetVisualWidthForCharacter (text[i], visualColumn, IndentationSize);
        }

        return visualColumn;
    }

    // TODO(VisualLineBuilder): replace with CellVisualLine.GetRelativeOffset once B1 lands.
    private int GetLogicalColumnFromVisualColumn (DocumentLine line, int visualColumn)
    {
        var text = _document!.GetText (line);
        var clampedVisual = Math.Max (0, visualColumn);
        var currentVisual = 0;

        for (var logical = 0; logical < text.Length; logical++)
        {
            var width = GetVisualWidthForCharacter (text[logical], currentVisual, IndentationSize);
            var nextVisual = currentVisual + width;

            if (nextVisual >= clampedVisual)
            {
                if (text[logical] == '\t' && clampedVisual > currentVisual)
                {
                    // Mouse click inside the visual span produced by '\t' snaps to the *nearest*
                    // logical edge (before vs. after). The midpoint rounds down to "before the tab".
                    // TODO(VisualLineBuilder): replace with CellVisualLine.GetRelativeOffset.
                    var midpoint = currentVisual + width / 2;

                    return clampedVisual > midpoint ? logical + 1 : logical;
                }

                return clampedVisual >= nextVisual ? logical + 1 : logical;
            }

            currentVisual = nextVisual;
        }

        return text.Length;
    }

    private static int GetVisualWidthForCharacter (char c, int visualColumn, int tabWidth)
    {
        if (c != '\t')
        {
            return 1;
        }

        var remainder = visualColumn % tabWidth;

        return remainder == 0 ? tabWidth : tabWidth - remainder;
    }

    private void EnsureCaretVisible ()
    {
        Rectangle viewport = Viewport;

        if (viewport.Width == 0 || viewport.Height == 0)
        {
            return;
        }

        var caretLine = GetCaretLineIndex ();
        var caretCol = GetCaretColumn ();
        var newY = viewport.Y;
        var newX = viewport.X;

        if (caretLine < newY)
        {
            newY = caretLine;
        }
        else if (caretLine >= newY + viewport.Height)
        {
            newY = caretLine - viewport.Height + 1;
        }

        if (caretCol < newX)
        {
            newX = caretCol;
        }
        else if (caretCol >= newX + viewport.Width)
        {
            newX = caretCol - viewport.Width + 1;
        }

        if (newX != viewport.X || newY != viewport.Y)
        {
            Viewport = viewport with { X = newX, Y = newY };
        }
    }
}

using System.Drawing;
using Terminal.Gui.Drawing;
using Terminal.Gui.Drivers;
using Terminal.Gui.Text.Document;
using Terminal.Gui.ViewBase;
using Attribute = Terminal.Gui.Drawing.Attribute;

namespace Terminal.Gui.Views;

public partial class Editor
{
    /// <inheritdoc />
    protected override bool OnDrawingContent (DrawContext? context)
    {
        if (_document is null)
        {
            return true;
        }

        Rectangle viewport = Viewport;
        Attribute normal = GetAttributeForRole (VisualRole.Normal);
        Attribute selected = GetAttributeForRole (VisualRole.Active);

        // The CS0618 here is the API's purpose: SyntaxHighlighter is [Obsolete] to warn
        // external callers that this is a stopgap (issue #32). The editor itself still has to
        // honor the property until Phase 6 lifts AvaloniaEdit's Highlighting/ pipeline (#28).
#pragma warning disable CS0618 // Type or member is obsolete
        ISyntaxHighlighter? syntaxHighlighter = SyntaxHighlighter;
#pragma warning restore CS0618 // Type or member is obsolete

        var hasSelection = HasSelection;
        var selStart = hasSelection ? SelectionStart : 0;
        var selEnd = hasSelection ? SelectionEnd : 0;

        PrepareSyntaxHighlighter (syntaxHighlighter, viewport.Y);

        for (var row = 0; row < viewport.Height; row++)
        {
            var lineIndex = viewport.Y + row;

            if (lineIndex < 0 || lineIndex >= _document.LineCount)
            {
                break;
            }

            DocumentLine line = _document.GetLineByNumber (lineIndex + 1);
            var text = _document.GetText (line);
#pragma warning disable CS0618 // Type or member is obsolete — see note at top of OnDrawingContent.
            IReadOnlyList<StyledSegment>? segments = syntaxHighlighter?.Highlight (text, SyntaxLanguage);
#pragma warning restore CS0618 // Type or member is obsolete
            var visibleStart = viewport.X;
            var visibleEnd = viewport.X + viewport.Width;

            DrawLineContent (
                row,
                text,
                visibleStart,
                visibleEnd,
                segments,
                normal,
                selected,
                line.Offset,
                hasSelection,
                selStart,
                selEnd);
        }

        SetAttribute (normal);
        UpdateCursor ();

        return true;
    }

    private void PrepareSyntaxHighlighter (ISyntaxHighlighter? syntaxHighlighter, int firstVisibleLineIndex)
    {
        if (syntaxHighlighter is null || _document is null)
        {
            return;
        }

        syntaxHighlighter.ResetState ();

        for (var lineIndex = 0; lineIndex < firstVisibleLineIndex && lineIndex < _document.LineCount; lineIndex++)
        {
            DocumentLine line = _document.GetLineByNumber (lineIndex + 1);
#pragma warning disable CS0618 // Type or member is obsolete — see note in OnDrawingContent.
            syntaxHighlighter.Highlight (_document.GetText (line), SyntaxLanguage);
#pragma warning restore CS0618 // Type or member is obsolete
        }
    }

    private void DrawLineContent (
        int row,
        string text,
        int visibleStart,
        int visibleEnd,
        IReadOnlyList<StyledSegment>? segments,
        Attribute normal,
        Attribute selected,
        int lineOffset,
        bool hasSelection,
        int selStart,
        int selEnd)
    {
        var visualColumn = 0;
        var segmentIndex = 0;
        var segmentEnd = segments is { Count: > 0 } ? segments[0].Text.Length : int.MaxValue;

        for (var i = 0; i < text.Length; i++)
        {
            while (segments is not null && i >= segmentEnd && segmentIndex + 1 < segments.Count)
            {
                segmentIndex++;
                segmentEnd += segments[segmentIndex].Text.Length;
            }

            Attribute attribute = segments is null
                ? normal
                : segments[segmentIndex].Attribute ?? normal;

            if (hasSelection && lineOffset + i >= selStart && lineOffset + i < selEnd)
            {
                attribute = selected;
            }

            var c = text[i];
            var width = GetVisualWidthForCharacter (c, visualColumn, TabWidth);
            var charVisualStart = visualColumn;
            var charVisualEnd = visualColumn + width;

            if (charVisualEnd <= visibleStart)
            {
                visualColumn = charVisualEnd;

                continue;
            }

            if (charVisualStart >= visibleEnd)
            {
                break;
            }

            var drawStart = Math.Max (charVisualStart, visibleStart);
            var drawEnd = Math.Min (charVisualEnd, visibleEnd);

            if (drawEnd > drawStart)
            {
                SetAttribute (attribute);
                AddStr (
                    drawStart - visibleStart,
                    row,
                    c == '\t' ? new (' ', drawEnd - drawStart) : c.ToString ());
            }

            visualColumn = charVisualEnd;
        }
    }

    private void UpdateCursor ()
    {
        if (!HasFocus || _document is null)
        {
            Cursor = new ();

            return;
        }

        Rectangle viewport = Viewport;
        var caretLine = GetCaretLineIndex ();
        var caretCol = GetCaretColumn ();
        var row = caretLine - viewport.Y;
        var col = caretCol - viewport.X;

        if (row < 0 || row >= viewport.Height || col < 0 || col >= viewport.Width)
        {
            Cursor = new ();

            return;
        }

        Point screen = ViewportToScreen (new Point (col, row));
        Cursor = new () { Position = screen, Style = CursorStyle.BlinkingBar };
    }

    /// <inheritdoc />
    protected override void OnDrawComplete (DrawContext? context)
    {
        base.OnDrawComplete (context);

        if (App?.Driver is { } driver)
        {
            DrawLineNumbers (driver);
        }
    }

    private void DrawLineNumbers (IDriver driver)
    {
        if (!_showLineNumbers || _document is null)
        {
            return;
        }

        var width = Padding.Thickness.Left;

        if (width <= 0)
        {
            return;
        }

        Rectangle viewport = Viewport;
        Rectangle screen = ViewportToScreen ();
        Region? clip = GetClip ();
        Attribute previous = driver.SetAttribute (GetAttributeForRole (VisualRole.Normal));

        SetClipToScreen ();

        try
        {
            for (var row = 0; row < viewport.Height; row++)
            {
                var lineIndex = viewport.Y + row;
                var text = lineIndex < _document.LineCount
                    ? (lineIndex + 1).ToString ().PadLeft (width - 1).PadRight (width)
                    : new string (' ', width);

                driver.Move (screen.X - width, screen.Y + row);
                driver.AddStr (text);
            }
        }
        finally
        {
            if (clip is not null)
            {
                SetClip (clip);
            }

            driver.SetAttribute (previous);
        }
    }
}

