    {
        _fileNameShortcut.Text = CurrentFilePath is null ? "<untitled>" : Path.GetFileName (CurrentFilePath);
        _fileNameShortcut.HelpText = CurrentFilePath ?? "No file";
        _fileNameShortcut.SetNeedsDraw ();
    }

